cadValueAfterAction: ValueChangeBeforeFunc = (value, fieldCpm, formCpm) => {
  const modelObj = value.origin as IFoundaton;

  // 赋值cad数据
  const needSet = ['MODELCLASS$CODE', 'MODELCLASS$NAME', 'MODELCLASS$TITLE', 'MODELCLASS'];
  if (modelObj['MODELCLASS']) {
    needSet.forEach(key => {
      fieldCpm.setValueOfDefault(key, modelObj[key]);
    });
  } else {
    needSet.forEach(key => {
      fieldCpm.setValueOfDefault(key, '');
    });
  }

  fieldCpm.setValueOfDefault('MODELTYPE', modelObj['MODELTYPE'] === 'Y');

  // 如果cad配置名称一致，则赋值cad名称
  if (formCpm.dppRender.innerSend?.['instance_NAME$']) {
    fieldCpm.setValueOfDefault('NAME$', formCpm.dppRender.innerSend?.['instance_NAME$']);
  }
  // 如果cad配置id一致，则赋值id
  if (formCpm.dppRender.innerSend?.['instance_ID$']) {
    fieldCpm.setValueOfDefault('ID$', formCpm.dppRender.innerSend?.['instance_ID$']);
  }
};

formTemplateChangeAction: ValueChangeBeforeFunc = (value, fieldCpm, formCpm) => {
  const needSet = [
    'PROJECTTYPE',
    'PROJECTTYPE$TITLE',
    'PROJECTTYPE$CLASS',
    'PROJECTTYPE$CLASSNAME',
    'PROJECTTYPE$MASTER',
    'PROJECTTYPE$FULLNAME'
  ];
  needSet.forEach(key => {
    fieldCpm.setValueOfDefault(key, value[key]);
  });
  return of(true);
};

sysGanttAssociatedAction: AssociatedActionFn = (params, ganttCpm) => {
  const startTask = params.startTask.origin.tableNode.origin as unknown as ITask;
  const endTask = params.endTask.origin.tableNode.origin as unknown as ITask;
  const tableCpm = ganttCpm.getTableCpm();
  const item: SaveBatchTaskRelationParam = {
    PRETASKGUID: startTask[SystemClassFieldEnum.GUID],
    PRETASKGUID$CLASS: startTask[SystemClassFieldEnum.CLASSGUID],
    PRETASKGUID$MASTER: startTask[SystemClassFieldEnum.MASTERFK],
    PRETASKGUID$CLASSNAME: startTask[SystemClassFieldEnum.CLASSNAME],
    TASKGUID: endTask[SystemClassFieldEnum.GUID],
    TASKGUID$CLASS: endTask[SystemClassFieldEnum.CLASSGUID],
    TASKGUID$MASTER: endTask[SystemClassFieldEnum.MASTERFK],
    TASKGUID$CLASSNAME: endTask[SystemClassFieldEnum.CLASSNAME],
    PROJECTGUID: startTask.OWNERPROJECT,
    PROJECTGUID$CLASS: startTask.OWNERPROJECT$CLASS,
    PROJECTGUID$MASTERFK: startTask.OWNERPROJECT$MASTER,
    PROJECTGUID$CLASSNAME: startTask.OWNERPROJECT$CLASSNAME,
    DELAYTIME: '0',
    PRETASKTYPE: params.linkType
  };
  // return of(true);
  return this.projectManageService.batchAddOrRemoveRelTask([item]).pipe(
    map(i => {
      if (i.data!.errorCnt !== 0) {
        this.message.error(i.data!.details![0].message as string);
        return true;
      }
      tableCpm.refreshNode(
        params.startTask.origin.tableNode,
        i.data!.details![0].data as unknown as Record<string, unknown>
      );
      ganttCpm.getChartCpm().upDataByNode(params.startTask.origin.tableNode);
      return true;
    }),
    catchError(i => of(false))
  );
};

sysGanttUpdateTimeAction: UpdateTimeActionFn = (params, ganttCpm) => {
  const itask = params.task.origin.tableNode.origin as unknown as ITask;
  const tableCpm = ganttCpm.getTableCpm();
  const changeParams = {};
  if (params.type === 'S') {
    changeParams['PLANSTARTTIME'] = params.changeParams.time;
  } else {
    changeParams['PLANFINISHTIME'] = params.changeParams.time;
  }
  const obj = {
    CLASSNAME$: itask.CLASSNAME$,
    GUID$: itask.GUID$,
    ...changeParams
  };
  return this.projectManageService.saveTask(obj).pipe(
    map(i => {
      tableCpm.refreshNode(params.task.origin.tableNode, i.data! as unknown as Record<string, unknown>);
      return params.task;
    }),
    catchError(i => of(params.task))
  );
};

