sysDeliveryStatisticExportAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const params = table.queryCondition.getRawValue();
  this.setLoading(event, true);
  if (table.getAllNodes().length === 0) {
    this.dppMessageService.error('project.message.error.noData');
    this.setLoading(event, false);
    return;
  }
  this.projectStatisticQueryService.exportDeliverable(params).subscribe({
    next: res => {
      if (res.success) {
        this.setLoading(event, false);
        const now = new Date();
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        const dateStr = `${year}${month}${day}`;
        const timestamp = String(Date.now()).slice(0, 9);

        const downloadUrl = window.URL.createObjectURL(res.data!);
        const link = document.createElement('a');
        link.href = downloadUrl;
        link.download = `${dateStr}${timestamp}.xls`;
        link.click();
        window.URL.revokeObjectURL(downloadUrl);
        this.dppMessageService.success('project.message.success.exportSuccess');
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

