sysSummaryTableExportAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const { modelManage, columnManage, api } = table.beans as BeanCollections;
  const columnLabels = columnManage.totalColumns.filter(col => col.key !== 'leftControl').map(col => col.label);
  const columnKeys = columnManage.totalColumns.filter(col => col.key !== 'leftControl').map(col => col.key);

  const params = table.queryCondition.getRawValue();
  this.setLoading(event, true);
  if (table.getAllNodes().length === 0) {
    this.dppMessageService.error('project.message.error.noData');
    this.setLoading(event, false);
    return;
  }
  const data = table.getAllNodes().map(node => node.origin);

  try {
    // 定义中文表头映射
    const headerMapping = columnKeys.reduce(
      (obj, num, index) => {
        obj[num] = this.dpptranslate.transform(columnLabels[index]!) ?? '';
        return obj;
      },
      {} as { [key: string]: string }
    );

    // 创建工作簿
    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet('汇总表');

    // 获取表头、添加表头行
    const headers = Object.values(headerMapping);
    const headerRow = worksheet.addRow(headers);

    // 设置表头样式：加粗、加大字体
    headerRow.eachCell(cell => {
      cell.font = {
        bold: true,
        size: 14
      };
      cell.alignment = {
        horizontal: 'center',
        vertical: 'middle'
      };
      cell.fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: 'FFE0E0E0' }
      };
      cell.border = {
        top: { style: 'thin' },
        left: { style: 'thin' },
        bottom: { style: 'thin' },
        right: { style: 'thin' }
      };
    });

    // 添加数据行
    data.forEach(row => {
      const rowData = columnKeys.map(key => row[key] || '');
      const dataRow = worksheet.addRow(rowData);

      // 设置数据行样式
      dataRow.eachCell((cell, colNumber) => {
        const originalKey = columnKeys[colNumber - 1];
        const originalValue = row[originalKey];

        // 只有当原始值严格等于 0 时，才强制设置格式
        if (originalValue === 0) {
          cell.value = 0;
          cell.numFmt = '0'; // 强制显示 0
        }
        cell.alignment = {
          horizontal: 'center',
          vertical: 'middle'
        };
        cell.border = {
          top: { style: 'thin' },
          left: { style: 'thin' },
          bottom: { style: 'thin' },
          right: { style: 'thin' }
        };
      });
    });

    // 设置列宽
    worksheet.columns.forEach((column, index) => {
      column.width = 18;
    });

    // 生成文件名：年月日 + 9位随机数
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');

    // 生成9位随机数
    const timestamp = String(Date.now()).slice(0, 9);

    const fileName = `${year}${month}${day}${timestamp}.xlsx`;

    // 导出文件
    workbook.xlsx
      .writeBuffer()
      .then(buffer => {
        const blob = new Blob([buffer]);
        const downloadUrl = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = downloadUrl;
        link.download = fileName;
        link.click();
        window.URL.revokeObjectURL(downloadUrl);

        this.setLoading(event, false);
        this.dppMessageService.success('project.message.success.exportSuccess');
      })
      .catch(error => {
        this.setLoading(event, false);
      });
  } catch (error) {
    this.setLoading(event, false);
  }
}

sysProjectTemplateTaskDragAction(event: RowDragEvent): Observable<boolean> {
  const tableCpm = event.beans.table;
  const ganttCpm = tableCpm.dppRender.innerSend!.getPageThis!().getComFnMapByName<GanttComponent>(
    CommandConstant.ProjectWbsCommand
  )!;

  const dragNode = event.dragNode;
  const dragNodeData = dragNode.origin as unknown as ITask;
  const dropNode = event.dropNode;
  const dropNodeData = dropNode.origin as unknown as ITask;
  const pos = event.pos;
  const allNodes = tableCpm.getAllNodes();

  let target = '';
  // pos是相对拖拽线的位置来的，dropNode可能是父，也可能是子
  // 1：放到dropNode的上面，-1：放到dropNode的下面
  // 0：放到dropNode下面，作为子，2：放到dropNode上面，作为子
  if (pos === 1) {
    // 同层移动，taget要分开计算
    // 如果dropNode是第一个子，表示拖到了根节点下第一个位置，targetNode为第一个子元素
    const index = dropNode.rowIndex! - 1 === 0 ? 1 : dropNode.rowIndex!;
    const targetNode = dropNode.beans.rowModel.rowsToDisplay[index];
    // 如果dropNode和targetNode的wbs长度不等，则targetNode还是取dropNode
    target = this.getTargetWbsOne(dragNode, targetNode, allNodes, dropNode);
  }
  if (pos === -1) {
    // 同层移动，taget要分开计算
    const targetNode = dropNode;
    target = this.getTargetWbs(dragNode, targetNode, allNodes, dropNode, 1);
  }
  if (pos === 0) {
    const targetNode = dropNode;
    // dragNode已经存在dropNode.children中，直接return
    const is = targetNode.children.some(node => node.origin['END2#GUID$'] === dragNode.origin['END2#GUID$']);
    if (is) {
      this.dppMessageService.error('子节点已存在！');
      return of(false);
    }
    target = this.generateTargetWbs(targetNode, 0.1 + targetNode.children.length * 0.1);
  }
  if (pos === 2) {
    const parentNode = dropNode['parentNode']!;
    const index = dropNode.rowIndex! - 1;
    const targetNode = dropNode.beans.rowModel.rowsToDisplay[index];

    // dragNode已经存在parentNode中，直接return
    const is = targetNode.children.some(node => node.origin['END2#GUID$'] === dragNode.origin['END2#GUID$']);
    if (is && targetNode.children.length > 0) {
      this.dppMessageService.error('子节点已存在！');
      return of(false);
    }
    const isSelf = targetNode.origin['END2#GUID$'] === dragNode.origin['END2#GUID$'];
    if (isSelf) {
      this.dppMessageService.error('不能自己拖拽给自己！');
      return of(false);
    }
    const len = targetNode.children.length === 0 ? 0.1 : parentNode.children.length;
    target = this.generateTargetWbs(targetNode, 0.1 + targetNode.children.length * 0.1);
  }
  const params: DropToSaveTaskParam = {
    source: dragNodeData.WBSNUMBER,
    target: target
  };

  const datas: Array<{ GUID$: string; CLASSGUID$: string; CLASSNAME$: string }> = [];
  const nodeMap = new Map<string, RowNode>();
  tableCpm.getAllNodes().forEach(i => {
    const task = i.origin as unknown as ITask;
    if (task.CLASSNAME$ === TaskTemplateOption.className) {
      datas.push({
        GUID$: task.GUID$,
        CLASSGUID$: task.CLASSGUID$,
        CLASSNAME$: task.CLASSNAME$
      });
    }
    nodeMap.set(task.GUID$, i);
  });
  const obss = new Array<
    Observable<{
      type: 'cell' | 'list';
      res: DppResponse<ITask | ITask[]>;
    }>
  >();
  obss.push(
    this.projectManageService.dropToSaveTask(params).pipe(
      map(i => {
        return {
          type: 'cell',
          res: i
        };
      })
    )
  );
  obss.push(
    this.projectManageService.listTasksDetails(datas).pipe(
      map(i => {
        return {
          type: 'list',
          res: i
        };
      })
    )
  );

  // return this.projectManageService.dropToSaveTask(param).pipe(
  //   map(i => {
  //     return true;
  //   })
  // );
  return new Observable<boolean>(observer => {
    from(obss)
      .pipe(concatMap(request => request))
      .subscribe({
        next: ress => {
          if (ress.type === 'list') {
            const details = ress.res.data as ITask[];
            details.forEach(item => {
              const rowNode = nodeMap.get(item.GUID$);
              if (rowNode) {
                rowNode.setData({
                  ...rowNode.origin,
                  ...item
                });
              }
            });
            if (ganttCpm) {
              tableCpm.afterQueryData.next(true);
            }
            observer.next(true);
            observer.complete();
          }
        },
        error: err => {
          observer.next(false);
        }
      });
  });
}

getWbsLevelComparison(dragNode: RowNode, targetNode: RowNode): DppSafeAny {
  // ① 分层
  // 1. targetNode的wbs和dragNode的wbs使用.分割后的数组长度进行比较，判断是同层拖拽还是跨层拖拽
  const dragNodeWbs = dragNode.origin['WBSNUMBER'].split('.');
  const targetNodeWbs = targetNode.origin['WBSNUMBER'].split('.');
  // 2. 跨层拖拽，还是使用this.generateTargetWbs(allNodes, dropNode);
  // 3. dragNodeWbs.length === targetNodeWbs.length --> 同层拖拽，targetNode['WBSNUMBER']

  // ② 从上往下，还是从下往上拖
  // 4. dragNode的wbs大于targetNode的wbs，从下往上拖，不动
  // 5. dragNode的wbs小于targetNode的wbs，从上往下拖，targetNode['WBSNUMBER']
  const isSameLevel = dragNodeWbs.length === targetNodeWbs.length;
  const isTopToBottom = Number(dragNodeWbs[dragNodeWbs.length - 1]) < Number(targetNodeWbs[targetNodeWbs.length - 1]);

  return { isSameLevel, isTopToBottom };
}

getTargetWbs(dragNode: RowNode, targetNode: RowNode, allNodes: RowNode[], dropNode: RowNode, direction = 0): string {
  const { isSameLevel, isTopToBottom } = this.getWbsLevelComparison(dragNode, targetNode);

  if (isSameLevel) {
    if (isTopToBottom) {
      const rowIndex = targetNode.rowIndex!;
      return dropNode.beans.rowModel.rowsToDisplay[rowIndex].origin['WBSNUMBER'];
    } else {
      return this.generateTargetWbs(targetNode, direction);
    }
  } else {
    return this.generateTargetWbs(targetNode, direction);
  }
}

getMaxIndex(list: string[], dropNode: RowNode): number {
  // 过滤出不包含点的元素
  const filteredList = list.filter(item => !!item).filter(itey => !itey.includes('.'));
  // 将字符串转为数字并找到最大值
  const maxValue = Math.max(...filteredList.map(item => parseInt(item, 10)));
  const node = dropNode.beans.rowModel.rowsToDisplay.find(node => node.origin['WBSNUMBER'] === maxValue.toString());
  if (node) {
    return node.rowIndex!;
  }
  return dropNode.rowIndex!;
}

generateTargetWbs(targetNode: RowNode, index: number = 0): string {
  const wbs = targetNode?.origin['WBSNUMBER'];

  if (!wbs) return ''; // 如果没有 wbs，返回空字符串

  // 找到最后一个小数点的位置
  const dotIndex = wbs.lastIndexOf('.');

  if (dotIndex === -1) {
    // 如果没有小数点，直接加上 index
    return (parseInt(wbs) + index).toString();
  }

  // 获取整数部分和小数部分
  const integerPart = wbs.slice(0, dotIndex);
  const decimalPart = wbs.slice(dotIndex + 1);

  // 取小数部分最后一位并加上 index
  const lastDecimalDigit = parseInt(decimalPart[decimalPart.length - 1]) + index;

  // 拼接新的 wbs
  const newDecimalPart = decimalPart.slice(0, decimalPart.length - 1) + lastDecimalDigit;

  return `${integerPart}.${newDecimalPart}`;
}

