sysTemplateTaskImportAction(event: EventInterface): void {
  this.setLoading(event, true);
  const project = this.getRootPageService(event).getInstanceData();
  const tableCpm = this.getContentCom(event) as unknown as DppTableComponent;
  debugger;
  const rootNode = tableCpm.getTreeNodes();
  const fileInput = document.createElement('input');
  fileInput.type = 'file';
  fileInput.accept = '.mpp';
  fileInput.style.display = 'none';
  fileInput.addEventListener('change', fileEvent => {
    const files = (fileEvent.target as HTMLInputElement).files;
    const rootData = rootNode[0].origin.HASEND2;
    const param = {
      CLASSNAME$: project?.['CLASSNAME$'],
      CLEARTASK: rootData,
      GUID$: project?.['GUID$']
    };
    const formData = new FormData();
    formData.append('file', files![0]);
    const blob = new Blob([JSON.stringify(param)], {
      type: 'application/json'
    });
    formData.append('object', blob);
    this.projectManageService.importProject(formData).subscribe({
      next: res => {
        if (res.success) {
          this.dppMessageService.success('systemSetting.organization.groupManagment.title.importSuccess');
          tableCpm.refreshData();
          this.setLoading(event, false);
        }
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
    fileInput.remove();
  });
  fileInput.addEventListener('cancel', fileEvent => {
    fileInput.remove();
    this.setLoading(event, false);
  });
  fileInput.click();
}

