  if (plannedStartDates?.length > 0) {
    processedData['PlanStartTime'] = plannedStartDates[0];
    processedData['PlanFinishTime'] = plannedStartDates[1];
  }
  return processedData;
}

private buildTaskSaveParams(formData: any, context: TaskContext, operation: TaskOperation): any {
  const { rowData, project, className } = context;
  const processedData = this.processFormData(formData);

  const baseParams = {
    ...processedData,
    CLASSNAME$: className,
    OPERATION: operation.type
  };

  switch (operation.type) {
    case 'ADDCHILD':
      return {
        ...baseParams,
        CURRENTTASK: rowData['GUID$'],
        OWNERPROJECT: project[SystemClassFieldEnum.GUID],
        OWNERPROJECT$CLASS: project[SystemClassFieldEnum.CLASSGUID],
        OWNERPROJECT$MASTER: project[SystemClassFieldEnum.MASTERFK],
        OWNERPROJECT$CLASSNAME: project[SystemClassFieldEnum.CLASSNAME],
        CURRENTTASK$CLASS: rowData['CLASSGUID$'],
        CURRENTTASK$MASTER: rowData['MASTERFK$'],
        PARENTTASK: rowData['GUID$'],
        PARENTTASK$CLASS: rowData['CLASSGUID$'],
        PARENTTASK$MASTER: rowData['MASTERFK$']
      };

    case 'ADDADJACENT':
      return {
        ...baseParams,
        CURRENTTASK: rowData['GUID$'],
        CURRENTTASK$CLASS: rowData['CLASSGUID$'],
        CURRENTTASK$MASTER: rowData['MASTERFK$'],
        PARENTTASK: rowData['PARENTTASK'],
        PARENTTASK$CLASS: rowData['PARENTTASK$CLASS'],
        PARENTTASK$MASTER: rowData['PARENTTASK$MASTER'],
        OWNERPROJECT: rowData['OWNERPROJECT'],
        OWNERPROJECT$CLASS: rowData['OWNERPROJECT$CLASS'],
        OWNERPROJECT$MASTER: rowData['OWNERPROJECT$MASTER']
      };

    default:
      return baseParams;
  }
}

private buildRefreshParams(operation: TaskOperation, context: TaskContext): TaskRefreshRequest {
  const { rowData, node, tableComp } = context;

  switch (operation.type) {
    case 'ADDCHILD':
    case 'ADDADJACENT':
      const allNode = tableComp.getAllNodes();
      const refreshItems: TaskRefreshItem[] = [];
      const nodeMap = new Map<string, RowNode>();

      allNode.forEach(item => {
        const data = item.origin;
        nodeMap.set(data['GUID$'], item);
        refreshItems.push({
          GUID$: data['GUID$'],
          CLASSGUID$: data['CLASSGUID$'],
          CLASSNAME$: data['CLASSNAME$']
        });
      });

      return {
        nodeMap,
        items: refreshItems
      };

    default:
      return {
        nodeMap: new Map<string, RowNode>(),
        items: []
      };
  }
}

