private updateTaskView(params: TaskViewUpdateParams): void {
  const { context, newTasks, refreshTasks = {}, operationType, nodeMap } = params;
  const { node, tableComp, route, ganttComp } = context;

  // 确保 newTasks 和 refreshTasks 都是数组
  const tasks = Array.isArray(newTasks) ? newTasks : [newTasks];
  const refreshData = Array.isArray(refreshTasks) ? refreshTasks : [refreshTasks];

  switch (operationType) {
    case 'ADDCHILD':
      tableComp.applyTransaction({
        add: tasks,
        route: route
      });

      // 如果有刷新数据，更新节点
      if (refreshData.length > 0) {
        refreshData.forEach(item => {
          const targetNode = nodeMap.get(item['GUID$']);
          if (targetNode) {
            targetNode.setData({
              ...targetNode.origin,
              ...item
            });
          }
        });
      }

      // 展开节点显示新增的子节点
      // node.isExpanded = false;
      node.isExpanded = true;
      ganttComp?.refreshChatData();
      break;

    case 'ADDADJACENT':
      // 相邻位置新建
      const parentNode = node.parentNode!;
      const addIndex = parentNode.childrenAfterFilter.findIndex(i => i === node) + 1;
      tableComp.applyTransaction({
        add: tasks,
        route: route.slice(0, route.length - 1),
        addIndex
      });

      // 如果有刷新数据，更新节点
      if (refreshData.length > 0) {
        refreshData.forEach(item => {
          const targetNode = nodeMap.get(item['GUID$']);
          if (targetNode) {
            targetNode.setData({
              ...targetNode.origin,
              ...item
            });
          }
        });
      }
      ganttComp?.refreshChatData();
      break;

    default:
      break;
  }
}

