private operateTaskHandle(event: EventInterface, type: OperateTaskType): void {
  const data = this.getRowData(event);
  const rowDataNode = this.getNode(event) as RowNode;
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  const ganttCpm = this.getRootPageService(event).getComFnMapByName<GanttComponent>(
    CommandConstant.ProjectWbsCommand
  )!;
  const instanceData = this.getRootPageService(event).getInstanceData();
  const taskStartType = instanceData['TASKSTARTTYPE$CODE'];
  this.setLoading(event, true);
  this.projectManageService
    .operateTask(data['GUID$'], data['CLASSGUID$'], type)
    .pipe(
      switchMap(i => {
        // Manual-手动触发
        if (taskStartType !== 'FrontDrive') {
          return of(i);
        }
        // 前置任务触发-不是完成/启动
        if (type !== 'complete' && type !== 'start') {
          return of(i);
        }
        // 前置任务触发-是完成/启动
        return this.projectManageService.listPostTasks(data['GUID$'], data['CLASSNAME$']).pipe(
          map(t => {
            return {
              type: 'post',
              currentData: i.data!,
              datas: t.data!
            };
          })
        );
      })
    )
    .subscribe({
      next: res => {
        if (res['type'] !== 'post') {
          const tranRes = res as DppResponse<ITask>;
          if (tranRes.success) {
            if (type === 'delete') {
              // if (rowDataNode.parentNode) {
              //   GanttEventUtil.refreshDataByNode(tableCpm, rowDataNode.parentNode);
              // } else {
              //   tableCpm.refreshData();
              // }
              const resDatas = tranRes.data as unknown as ITask[];
              GanttEventUtil.deleteNodeBySimple(tableCpm, ganttCpm, rowDataNode, this.projectManageService);
              if (resDatas.length > 0) {
                const tableNodes = tableCpm.getFlatRootNodes();
                tableNodes.forEach(i => {
                  const temp = resDatas.find(t => t.GUID$ === i.origin['GUID$']);
                  if (temp) {
                    GanttEventUtil.upDataByNode(tableCpm, i, temp, ganttCpm);
                  }
                });
              }
            } else {
              // 新增逻辑：手动触发下，收集需要刷新的节点并批量调用listTasksDetails
              if (taskStartType === 'Manual') {
                this.handleDetails({ rowDataNode, tableCpm, ganttCpm, event });
              }
              // 刷当前行
              // GanttEventUtil.upDataByNode(tableCpm, rowDataNode, tranRes.data!, ganttCpm);
            }
            this.dppMessageService.success('common.operation.operationSuccess');
          }
        } else {
          const resDatas = res['datas'] as ITask[];
          const tableNodes = tableCpm.getFlatRootNodes();
          GanttEventUtil.upDataByNode(tableCpm, rowDataNode, res['currentData'], ganttCpm);
          if (resDatas.length === 0) {
            this.setLoading(event, false);
            return;
          }
          tableNodes.forEach(i => {
            const temp = resDatas.find(t => t.GUID$ === i.origin['GUID$']);
            if (temp) {
              GanttEventUtil.upDataByNode(tableCpm, i, temp, ganttCpm);
            }
          });
        }

        this.setLoading(event, false);
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
}

