sysTaskBatchDeleteAction(event: EventInterface): void {
  const context = this.initializeComponentsBatch(event);
  const { tableComp, ganttComp } = context;
  this.setLoading(event, true);
  const deleteParams: TaskRefreshItem[] = [];
  const deleteNodeMap = new Map<string, RowNode>();
  const refreshParams: TaskRefreshItem[] = [];
  const refreshNodeMap = new Map<string, RowNode>();
  const allNode = tableComp.getAllNodes();
  const selectNodes = tableComp.getCheckedNodeList();

  selectNodes.forEach(item => {
    const data = item.origin;
    deleteNodeMap.set(data['GUID$'], item);
    deleteParams.push({
      GUID$: data['GUID$'],
      CLASSGUID$: data['CLASSGUID$'],
      CLASSNAME$: data['CLASSNAME$']
    });
  });

  allNode.forEach(item => {
    const data = item.origin;
    // 如果有节点删除失败，也是需要刷新的
    // if (deleteNodeMap.has(data['GUID$'])) {
    //   return;
    // }
    refreshNodeMap.set(data['GUID$'], item);
    refreshParams.push({
      GUID$: data['GUID$'],
      CLASSGUID$: data['CLASSGUID$'],
      CLASSNAME$: data['CLASSNAME$']
    });
  });
  const del$ = this.projectManageService.batchOperateTask(deleteParams, 'delete');

  const refresh$ = this.projectManageService.listTasksDetails(refreshParams);
  del$
    .pipe(
      switchMap(delRes =>
        iif(
          () => !!delRes.success,
          refresh$.pipe(map(refreshRes => ({ delRes, refreshRes }))),
          of({ delRes, refreshRes: { data: [] } })
        )
      )
    )
    .subscribe({
      next: ({ delRes, refreshRes }) => {
        if (delRes.success) {
          const batchRes = delRes.data! || {};
          const { errorCnt, totalCnt, successCnt, details } = batchRes;
          if (totalCnt === successCnt) {
            tableComp.deleteNode(selectNodes);
            const newData = refreshRes.data || [];
            if (newData.length > 0) {
              newData.forEach(item => {
                const targetNode = refreshNodeMap.get(item['GUID$']);
                if (targetNode) {
                  targetNode.setData({
                    ...targetNode.origin,
                    ...item
                  });
                }
              });
            }
            // 删除成功后刷新甘特图
            ganttComp?.refreshChatData();
          } else {
            const successDetails = details.filter(i => i.result === 'SUCCESS');
            const needDeleteNodes = selectNodes.filter(i => {
              const data = i.origin;
              return successDetails.some(j => j.data['GUID$'] === data['GUID$']);
            });
            tableComp.deleteNode(needDeleteNodes);
            const newData = refreshRes.data || [];
            if (newData.length > 0) {
              newData.forEach(item => {
                const targetNode = refreshNodeMap.get(item['GUID$']);
                if (targetNode) {
                  targetNode.setData({
                    ...targetNode.origin,
                    ...item
                  });
                }
              });
            }
            // 删除成功后刷新甘特图
            ganttComp?.refreshChatData();
          }
          const batchParams: BatchParams = {
            tableCpm: tableComp,
            ganttCpm: ganttComp,
            tranPipe: this.tranPipe,
            batchDatas: delRes.data!,
            message: this.dppMessageService,
            as: this.as,
            bs: this.getExeCom<DppButtonComponent>(event),
            type: 'complete',
            projectService: this.projectManageService
          };
          GanttEventUtil.batchHandle(batchParams);
        }
        this.setLoading(event, false);
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
}

private operateTaskBatchHandle(event: EventInterface, type: OperateTaskType): void {
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  const rowDataNodes = tableCpm.getCheckedNodeList();
  let datas = rowDataNodes.map(i => {
    return {
      GUID$: i.origin['GUID$'],
      CLASSGUID$: i.origin['CLASSGUID$'],
      CLASSNAME$: i.origin['CLASSNAME$']
    };
  });
  datas = datas.filter(item => {
    return item['CLASSNAME$'] !== 'Project';
  });
  if (!datas) return;
  // const rowDataNodes = tableCpm.getCheckedNodes();
  const ganttCpm = this.getRootPageService(event).getComFnMapByName<GanttComponent>(
    CommandConstant.ProjectWbsCommand
  )!;
  const instanceData = this.getRootPageService(event).getInstanceData();
  const taskStartType = instanceData['TASKSTARTTYPE$CODE'];
  this.setLoading(event, true);
  this.projectManageService
    .batchOperateTask(datas, type)
    .pipe(
      switchMap(i => {
        if (taskStartType !== 'FrontDrive') {
          return of(i);
        }
        if (type !== 'complete' && type !== 'start') {
          return of(i);
        }
        if (i.data?.totalCnt === i.data?.errorCnt) {
          return of(i);
        }
        const obss = new Array<Observable<DppResponse<ITask[]>>>();
        i.data!.details.forEach(t => {
          if (t.result === 'SUCCESS') {
            obss.push(this.projectManageService.listPostTasks(t.data['GUID$']!, t.data['CLASSNAME$']!));
          }
        });
        return forkJoin(obss).pipe(
          map(t => {
            let arr = new Array<ITask>();
            t.forEach(item => {
              arr = arr.concat(item.data || []);
            });
            return {
              type: 'post',
              currentRes: i,
              datas: arr
            };
          })
        );
      })
    )
    .subscribe({
      next: res => {
        const fn = (tranRes: DppResponse<IBatchData>): void => {
          if (tranRes.success) {
            const batchParams: BatchParams = {
              tableCpm,
              ganttCpm,
              tranPipe: this.tranPipe,
              batchDatas: tranRes.data!,
              message: this.dppMessageService,
              type,
              as: this.as,
              bs: this.getExeCom<DppButtonComponent>(event),
              projectService: this.projectManageService
            };
            GanttEventUtil.batchHandle(batchParams);
          }
        };
        if (res['type'] !== 'post') {
          const tranRes = res as DppResponse<IBatchData>;
          fn(tranRes);
        } else {
          fn(res['currentRes']);
          const resDatas = res['datas'] as ITask[];
          const tableNodes = tableCpm.getFlatRootNodes();
          if (resDatas.length === 0) {
            this.setLoading(event, false);
            return;
          }
          tableNodes.forEach(i => {
            const temp = resDatas.find(t => t.GUID$ === i.origin['GUID$']);
            if (temp) {
              GanttEventUtil.upDataByNode(tableCpm, i, temp, ganttCpm);
            }
          });
        }
        // 新增逻辑：手动触发下，收集需要刷新的节点并批量调用listTasksDetails
        if (taskStartType === 'Manual') {
          this.batchHandleDetails({ rowDataNodes, tableCpm, ganttCpm, event });
        }
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
}

