sysTaskImportAction(event: EventInterface): void {
  this.setLoading(event, true);
  // const bs = this.getExeCom(event) as DppButtonComponent;
  const ganttCpm = this.getRootPageService(event).getComFnMapByName<GanttComponent>(
    CommandConstant.ProjectWbsCommand
  )!;
  const tableCpm = ganttCpm.getTableCpm();
  const tableData = tableCpm.getDisplayedNodes();
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  if (tableData.length > 1) {
    const warning = this.tranPipe.transform('common.button.warning');
    this.as.confirm('task.command.ClearAgainExport', {
      title: warning,
      footer: {
        nzOnOk: () => {
          commonImport();
        },
        nzOnCancel: () => {
          this.setLoading(event, false);
        }
      }
    });
  } else {
    commonImport();
  }

  function commonImport(): void {
    const project = that.getRootPageService(event).getInstanceData();
    const rootNode = tableCpm.getTreeNodes();
    const fileInput = document.createElement('input');
    fileInput.type = 'file';
    fileInput.accept = '.mpp,.xlsx';
    fileInput.style.display = 'none';
    fileInput.addEventListener('change', fileEvent => {
      const files = (fileEvent.target as HTMLInputElement).files;
      const rootData = rootNode[0].origin.HASEND2;
      const param = {
        CLASSNAME$: project?.['CLASSNAME$'],
        CLEARTASK: rootData,
        GUID$: project?.['GUID$']
      };
      const formData = new FormData();
      formData.append('file', files![0]);
      const blob = new Blob([JSON.stringify(param)], {
        type: 'application/json'
      });
      formData.append('object', blob);
      that.projectManageService.importProject(formData).subscribe({
        next: res => {
          if (res.success) {
            const errorFile = res.data?.['size'];
            if (errorFile) {
              that.dppMessageService.error('gantt.filed.FailedInspection');
              const fileName = files?.[0]?.name;
              const url = window.URL.createObjectURL(res.data);
              const link = document.createElement('a');
              link.target = '_blank';
              link.download = fileName!;
              link.href = url;
              link.click();
              window.URL.revokeObjectURL(url);
            } else {
              that.dppMessageService.success('systemSetting.organization.groupManagment.title.importSuccess');
              tableCpm.refreshData(rootNode[0]);
            }
            that.setLoading(event, false);
          }
        },
        error: res => {
          that.setLoading(event, false);
        }
      });
      fileInput.remove();
    });
    fileInput.addEventListener('cancel', fileEvent => {
      fileInput.remove();
      that.setLoading(event, false);
    });
    fileInput.click();
  }
}

sysTaskExportAction(event: EventInterface): void {
  const project = this.getRootPageService(event).getInstanceData();
  // const bs = this.getExeCom(event) as DppButtonComponent;
  const param = {
    CLASSNAME$: project?.['CLASSNAME$'],
    GUID$: project?.['GUID$'],
    type: '',
    exportFieldList: [] as string[][]
  };
  const ganttCpm = this.getRootPageService(event).getComFnMapByName<GanttComponent>(
    CommandConstant.ProjectWbsCommand
  )!;
  const tableCpm = ganttCpm.getTableCpm();
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  this.setLoading(event, true);

  const modal = this.as.openModal(
    {
      title: 'task.command.SelectExportFormat',
      content: DppFormComponent,
      isInteractive: false,
      centered: true,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal.close();
            that.setLoading(event, false);
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(data: DppFormComponent) {
            this.loading = true;
            if (data.onSubmit()) {
              const formData = data.getFormData();
              const { columnManage } = tableCpm.beans as BeanCollections;
              const models = columnManage.getCols();
              models.forEach((model: DppColumn) => {
                if (model.isVisible() && model.getColId() !== 'leftControl' && model.getColId() !== 'operation') {
                  const key = model.getColDef()?.key!;
                  const label = that.tranPipe.transform(model.getColDef()?.label!);
                  param.exportFieldList.push([key, label]);
                }
              });
              param.type = formData?.['TYPE'];
              that.projectManageService.exportProject(param).subscribe({
                next: res => {
                  if (res.success && res.data) {
                    const fileName = project?.['FULLNAME$'];
                    const url = window.URL.createObjectURL(res.data);
                    const link = document.createElement('a');
                    link.target = '_blank';
                    link.download = `${fileName}.${formData?.['TYPE'] === 'xml' ? 'xml' : 'xlsx'}`;
                    link.href = url;
                    link.click();
                    window.URL.revokeObjectURL(url);
                    that.dppMessageService.success('systemSetting.organization.groupManagment.title.exportSuccess');
                  }
                  modal.close();
                  that.setLoading(event, false);
                  this.loading = false;
                },
                error: () => {
                  this.loading = false;
                  that.setLoading(event, false);
                }
              });
            } else {
              this.loading = false;
            }
          }
        }
      ]
    },
    { dppRender: { name: 'sysProjectTaskExportForm', mParams: { mode: ModeTypeEnum.EDIT } } }
  );
  modal.afterClose.subscribe(() => {
    this.setLoading(event, false);
  });
}

