      obss.push(
        this.projectManageService.listTasksDetails(datas).pipe(
          map(i => {
            return {
              type: 'list',
              res: i
            };
          })
        )
      );

      from(obss)
        .pipe(concatMap(request => request))
        .subscribe({
          next: ress => {
            if (ress.type === 'list') {
              const details = ress.res.data as ITask[];
              details.forEach(item => {
                tableCpm.refreshNode(nodeMap.get(item.GUID$)!, item as unknown as Record<string, unknown>);
