            this.setLoading(event, false);
          }
        });
    },
    this.dppMessageService,
    render
  );
}

sysTaskCopyNewAciton(event: EventInterface): void {
  const context = this.initializeComponents(event);
  const { tableComp, ganttComp, node, rowData, route } = context;
  const params = {
    ...rowData,
    OPERATION: 'ADDADJACENT',
    // CLASSNAME$: 'PMTask',
    CURRENTTASK: rowData['GUID$'],
    CURRENTTASK$CLASS: rowData['CLASSGUID$'],
    CURRENTTASK$MASTER: rowData['MASTERFK$']
  };
  params['GUID$'] = '';
  params.TASKTYPE = '';
  this.setLoading(event, true);

  const refreshParams: TaskRefreshItem[] = [];
  const refreshNodeMap = new Map<string, RowNode>();
  const allNode = tableComp.getAllNodes();
  allNode.forEach(item => {
    const data = item.origin;
    refreshNodeMap.set(data['GUID$'], item);
    refreshParams.push({
      GUID$: data['GUID$'],
      CLASSGUID$: data['CLASSGUID$'],
      CLASSNAME$: data['CLASSNAME$']
    });
  });

  const save$ = this.projectManageService.saveTask(params);
  const refresh$ = this.projectManageService.listTasksDetails(refreshParams);
  save$
    .pipe(
      switchMap(saveRes =>
        iif(
          () => !!saveRes.success,
          refresh$.pipe(map(refreshRes => ({ saveRes, refreshRes }))),
          of({ saveRes, refreshRes: { data: [] } })
        )
      )
    )
    .subscribe({
      next: ({ saveRes, refreshRes }) => {
        if (saveRes.success) {
          const newTask = saveRes.data;
          tableComp.applyTransaction({
            add: [newTask],
            route: route.slice(0, route.length - 1)
          });

          const redreshData = refreshRes.data || [];
          if (redreshData.length > 0) {
            redreshData.forEach(item => {
              const targetNode = refreshNodeMap.get(item['GUID$']);
              if (targetNode) {
                targetNode.setData({
                  ...targetNode.origin,
                  ...item
                });
              }
            });
          }
          this.setLoading(event, false);
          ganttComp?.refreshChatData();
        }
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
}

sysTaskPasteAciton(event: EventInterface): void {
  const copyMap = this.clipBoardService.getValuesByType(clipBoardTypeEnum.OBJECT_TYPE);
  if (!copyMap) {
    this.dppMessageService.warning('common.operation.NoObjectCopied');
    return;
  }
  const copyTasks = new Array<ITask>();
  copyMap.forEach(item => {
    if (item['type'] === TaskOption.className) {
      copyTasks.push(item['origin']);
    }
  });
  if (copyTasks.length === 0) {
    this.dppMessageService.warning('common.operation.NoTaskObjectCopied');
    return;
  }
  const context = this.initializeComponents(event);
  const { tableComp, ganttComp, node, rowData, route, project } = context;
  const copyTaskParams = copyTasks.map(i => {
    const param = {
      ...i,
      OPERATION: 'ADDCHILD',
      CURRENTTASK: rowData['GUID$'],
      CURRENTTASK$CLASS: rowData['CLASSGUID$'],
      CURRENTTASK$MASTER: rowData['MASTERFK$'],
      OWNERPROJECT: project['GUID$'],
      OWNERPROJECT$CLASS: project['CLASSGUID$'],
      OWNERPROJECT$MASTER: project['MASTERFK$'],
      PARENTTASK: rowData['GUID$'],
      PARENTTASK$CLASS: rowData['CLASSGUID$'],
      PARENTTASK$MASTER: rowData['MASTERFK$']
    };
    param['GUID$'] = '';
    param.TASKTYPE = '';
    return param;
  });

  this.setLoading(event, true);
  const refreshParams: TaskRefreshItem[] = [];
  const refreshNodeMap = new Map<string, RowNode>();
  const allNode = tableComp.getAllNodes();
  allNode.forEach(item => {
    const data = item.origin;
    refreshNodeMap.set(data['GUID$'], item);
    refreshParams.push({
      GUID$: data['GUID$'],
      CLASSGUID$: data['CLASSGUID$'],
      CLASSNAME$: data['CLASSNAME$']
    });
  });

  const create$ = this.projectManageService.batchCreateTask(copyTaskParams);
  const refresh$ = this.projectManageService.listTasksDetails(refreshParams);
  create$
    .pipe(
      switchMap(saveRes =>
        iif(
          () => !!saveRes.success,
          refresh$.pipe(map(refreshRes => ({ saveRes, refreshRes }))),
          of({ saveRes, refreshRes: { data: [] } })
        )
      )
    )
    .subscribe({
      next: ({ saveRes, refreshRes }) => {
        if (saveRes.success) {
          const batchRes = saveRes.data!;
          const { successCnt, totalCnt, details } = batchRes;
          if (totalCnt === successCnt) {
            const newTasks = details.filter(i => i.result === 'SUCCESS').map(i => i.data);
            const filteredTasks = this.tableUtil.filterTasks(newTasks);
            console.log(filteredTasks);

            tableComp.applyTransaction({
              add: filteredTasks,
              route: route
            });
            const redreshData = refreshRes.data || [];
            if (redreshData.length > 0) {
              redreshData.forEach(item => {
                const targetNode = refreshNodeMap.get(item['GUID$']);
                if (targetNode) {
                  targetNode.setData({
                    ...targetNode.origin,
                    ...item
                  });
                }
              });
            }
            node.isExpanded = true;
            this.setLoading(event, false);
          } else {
            const successDetails = details.filter(i => i.result === 'SUCCESS');
            const newTasks = successDetails.map(i => i.data);
            const filteredTasks = this.tableUtil.filterTasks(newTasks);

            tableComp.applyTransaction({
              add: filteredTasks,
              route: route
            });
            const redreshData = refreshRes.data || [];
            if (redreshData.length > 0) {
              redreshData.forEach(item => {
                const targetNode = refreshNodeMap.get(item['GUID$']);
                if (targetNode) {
                  targetNode.setData({
                    ...targetNode.origin,
                    ...item
                  });
                }
              });
            }
            const batchParams: BatchParams = {
              tableCpm: tableComp,
              ganttCpm: ganttComp,
              tranPipe: this.tranPipe,
              batchDatas: saveRes.data!,
              message: this.dppMessageService,
              as: this.as,
              bs: this.getExeCom<DppButtonComponent>(event),
              type: 'complete',
              projectService: this.projectManageService
            };
            GanttEventUtil.batchHandle(batchParams);
            node.isExpanded = true;
            this.setLoading(event, false);
          }
          ganttComp?.refreshChatData();
        }
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
}

