        const ganttCpm = tableCpm.dppRender.innerSend!.getPageThis!().getComFnMapByName<GanttComponent>(
          CommandConstant.ProjectWbsCommand
        )!;

        GanttEventUtil.upDataByNode(tableCpm, rowDataNode, i.data!, ganttCpm);
      }
      return i;
    })
  );
}

sysProjectTaskDragAction(event: RowDragEvent): Observable<boolean> {
  const context = this.buildDropParamsAndContext(event);
  if (!context) {
    return of(false);
  }
  const { tableComp, ganttComp, params } = context;

  const refreshParams: TaskRefreshItem[] = [];
  const nodeMap = new Map<string, RowNode>();
  const allNodes = tableComp.getAllNodes();

  allNodes.forEach(item => {
    const data = item.origin;
    nodeMap.set(data['GUID$'], item);
    refreshParams.push({
      GUID$: data['GUID$'],
      CLASSGUID$: data['CLASSGUID$'],
      CLASSNAME$: data['CLASSNAME$']
    });
  });

  const dropSave$ = this.projectManageService.dropToSaveTask(params);
  const refresh$ = this.projectManageService.listTasksDetails(refreshParams);
  return dropSave$.pipe(
    switchMap(saveRes =>
      iif(
        () => !!saveRes.success,
        refresh$.pipe(map(refreshRes => ({ saveRes, refreshRes }))),
        of({ saveRes, refreshRes: { data: [] } })
      )
    ),
    map(({ saveRes, refreshRes }) => {
      if (saveRes.success) {
        const newData = refreshRes.data || [];
        if (newData.length > 0) {
          newData.forEach(i => {
            const node = nodeMap.get(i['GUID$']);
            if (node) {
              node.setData({
                ...node.origin,
                ...i
              });
            }
          });
        }
      }
      return saveRes.success;
    }),
    catchError(error => {
      console.error('拖拽保存失败:', error);
      return of(false);
    })
  );
}

