sysTaskDetailSaveAction(event: EventInterface): void {
  const table = this.getTrigger(event) as unknown as DppTableComponent;
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.['config']?.['data'];
  const taskFullName = instanceData['GUID$'];
  const ganttTable = this.getTrigger(event) as unknown as DppTableComponent;
  const allGanttNode = ganttTable['dppFlattenNodes'];
  const checkedTaskNode = allGanttNode.find(item => item.origin['GUID$'] === taskFullName);
  const ganttCpn = ganttTable.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand);
  this.getNode(event);
  const rowData = this.getRowData(event);
  const node = table.getFlatRootNodes().find(item => item.origin['GUID$'] === taskFullName) as RowNode;
  const form = this.getContentCom(event) as unknown as DppFormComponent;
  const chanceFormData = form.getFormChanceData() as object;
  if (JSON.stringify(chanceFormData) === '{}') {
    this.dppMessageService.info('project.message.error.dataNotModified');
    return;
  }
  const CLASSNAME$ = rowData['CLASSNAME$'];
  const GUID$ = rowData['GUID$'];
  const params = {
    CLASSNAME$,
    GUID$,
    ...chanceFormData
  };
  const isValid = form.onSubmit();
  if (!isValid) {
    return;
  }
  this.projectManageService.saveTask(params).subscribe(res => {
    if (!table) return;
    if (!res.data) return;
    form.callback({
      action: EventCallbacksActionName.UPDATE,
