sysSaveAsProjectAction(event: EventInterface): void {
  this.setLoading(event, true);
  const rootPage = this.getRootPageService(event);
  let instanceData = rootPage.getInstanceData();
  const table = this.getContentCom(event) as DppTableComponent;
  if (Object.keys(instanceData).length === 0) instanceData = this.getRowData(event);
  const formParams: IFormRender = {
    name: 'sysProjectNewStepForm;class_Project_dialogForm',
    mParams: {
      mode: ModeTypeEnum.EDIT,
      isObject: false,
      expression: 'FROMTEMPLATE:editable=false;PROJECTTYPE:editable=false'
    },
    data: {}
  };
  const needSetField = [
    'CLASSNAME$',
    // 'FROMTEMPLATE',
    // 'FROMTEMPLATE$CLASSNAME',
    // 'FROMTEMPLATE$CLASS',
    // 'FROMTEMPLATE$ICON$',
    // 'FROMTEMPLATE$FULLNAME',
    'PROJECTTYPE',
    'PROJECTTYPE$CLASS',
    'PROJECTTYPE$NAME',
    'PROJECTTYPE$FULLNAME',
    'EXECUTOR',
    'EXECUTOR$ID',
    'EXECUTOR$FULLNAME',
    'EXECUTOR$NAME',
    'PLANSTARTTIME',
    'PLANFINISHTIME',
    'IMPORTANCELEVEL',
    'IMPORTANCELEVEL$NAME',
    'IMPORTANCELEVEL$TITLE',
    'IMPORTANCELEVEL$CODE',
    'PROGRAMTYPE',
    'PROGRAMTYPE$NAME',
    'PROGRAMTYPE$TITLE',
    'PROGRAMTYPE$CODE'
  ];
  needSetField.forEach(key => {
    formParams.data![key] = instanceData[key];
  });
  formParams.data!['FROMTEMPLATE'] = instanceData['GUID$'];
  formParams.data!['FROMTEMPLATE$CLASSNAME'] = instanceData['CLASSNAME$'];
  formParams.data!['FROMTEMPLATE$CLASS'] = instanceData['CLASSGUID$'];
  formParams.data!['FROMTEMPLATE$ICON$'] = instanceData['ICON$'];
  formParams.data!['FROMTEMPLATE$FULLNAME'] = instanceData['FULLNAME$'];

  formParams.data!['STARTOREND'] = instanceData['PLANSTARTTIME'] ? 'PLANSTARTTIME' : 'PLANFINISHTIME';
  formParams.data!['TIME'] = instanceData['PLANSTARTTIME'] || instanceData['PLANFINISHTIME'];

  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  const saveFn = (that: DppSafeAny, formCpn: DppFormComponent, afterFn?: (data: DppSafeAny) => void): void => {
    formCpn.setLoading(true);
    const isValid = formCpn.onSubmit();
    const formData = formCpn.getFormData<IBaseData>();
    // 处理开始/结束时间
    formData[formData['STARTOREND']] = formData['TIME'];
    delete formData['STARTOREND'];
    delete formData['STARTOREND$TITLE'];
    delete formData['TIME'];
    const params = {
      CLASSGUID$: instanceData['CLASSGUID$'],
      GUID$: instanceData['GUID$'],
      CLASSNAME$: instanceData['CLASSNAME$'],
      ...formData
    };
    if (isValid) {
      _this.projectManageService.getProjectUserResign(params.CLASSNAME$, params.GUID$).subscribe(res => {
        if (res.success) {
          const content = res.data as any;
          if (content['message']) {
            const tipModal = _this.as.openModal({
              full: 'false',
              linkType: 'modal',
              title: 'common.button.warning',
              isInteractive: false,
              closable: false,
              content: `${content['message']}`,
              footer: [
                {
                  label: 'common.button.confirm',
                  type: 'primary',
                  onClick: () => {
                    _this.projectManageService.saveAsProject(params as DppSafeAny).subscribe({
                      next: res => {
                        if (res.success) {
                          _this.dppMessageService.success('common.operation.operationSuccess');
                          modal.close();
                          formCpn.setLoading(false);
                          _this.setLoading(event, false);
                          if (table.type === UIModelTypeEnum.TABLE) {
                            table?.refreshData();
                          }
                          if (afterFn && typeof afterFn === 'function' && res.data) {
                            afterFn(res.data);
                          }
                        }
                      },
                      error: error => {
                        formCpn.setLoading(false);
                        _this.setLoading(event, false);
                      }
                    });
                    tipModal.close();
                  }
                }
              ]
            }) as DppNzModalRef;
          } else {
            _this.projectManageService.saveAsProject(params as DppSafeAny).subscribe({
              next: res => {
                if (res.success) {
                  _this.dppMessageService.success('common.operation.operationSuccess');
                  modal.close();
                  formCpn.setLoading(false);
                  _this.setLoading(event, false);
                  if (table.type === UIModelTypeEnum.TABLE) {
                    table?.refreshData();
                  }
                  if (afterFn && typeof afterFn === 'function' && res.data) {
                    afterFn(res.data);
                  }
                }
                that.loading = false;
              },
              error: error => {
                that.loading = false;
                formCpn.setLoading(false);
                _this.setLoading(event, false);
              }
            });
          }
        }
      });
    } else {
      that.loading = false;
      formCpn.setLoading(false);
      _this.setLoading(event, false);
    }
  };
  const modal = this.as.openModal(
    {
      title: 'project.project.saveAsProject',
      width: '700px',
      height: 'auto',
      closable: true,
      bodyStyle: {
        minHeight: '100px',
        maxHeight: '600px',
        overflow: 'scroll'
      },
      content: DppFormComponent,
      footer: [
        // {
        //   label: 'common.button.reset',
        //   type: 'default',
        //   onClick: formCpn => {
        //     formCpn?.reset();
        //   }
        // },
        {
          label: 'project.command.saveAndClose',
          type: 'default',
          onClick(formCpn: DppFormComponent) {
            this.loading = true;
            saveFn(this, formCpn);
          }
        },
        {
          label: 'project.command.saveAndContinue',
          type: 'primary',
          onClick(formCpn: DppFormComponent) {
            this.loading = true;
            saveFn(this, formCpn, data => {
              const { CLASSNAME$, GUID$ } = data;
              const routePath = `/instance?className=${CLASSNAME$}&guid=${GUID$}`;
              _this.as.openBlank({ routePath, title: `${CLASSNAME$}-${GUID$}` });
            });
          }
        }
      ],
      onCancel: () => {
        this.setLoading(event, false);
      }
    },
    {
      dppRender: formParams
    }
  );
}

