sysStartApprovalProcessAction(event: EventInterface): void {
  const rootPage = this.getRootPageService(event);
  const rowData = this.getRowData(event) as IFoundaton;
  const instanceData = rootPage.getInstanceData();
  const gattCpn = rootPage.getComFnMapByName(CommandConstant.ProjectWbsCommand) as GanttComponent;
  const table = gattCpn?.getTableCpm();
  let taskHasEND2 = false;

  const loadRoot$ = (): Observable<DppSafeAny> => {
    return table
      ? of([...table.getDisplayedData()])
      : this.projectManageService
          .getListRoot({
            GUID$: rowData.GUID$,
            CLASSNAME$: rowData.CLASSNAME$
          })
          .pipe(map(res => (res.success && res.data ? res.data : {})));
  };

  const params: ScalingOrRearParam = {
    project: {
      GUID$: instanceData['GUID$'],
      CLASSNAME$: instanceData['CLASSNAME$']
    }
  };
  this.projectManageService.taskScalingOrRear(params, 'rear').subscribe({
    next: res => {
      if (res.success) {
        startApprovalProcessFunc();
      }
    },
    error: error => {
      this.setLoading(event, false);
    }
  });
  const startApprovalProcessFunc: () => void = () => {
    const params: IFormRender = {
      name: 'sysStartApprovalProcessForm',
      mParams: {
        mode: ModeTypeEnum.EDIT,
        isObject: false
      },
      data: {
        type: 'workFlowTemplate',
        classGuid: instanceData['CLASSGUID$'],
        className: instanceData['CLASSNAME$'],
        guid: instanceData['GUID$'],
        NAME: instanceData['FULLNAME$'],
        DESCRIPTION: instanceData['FULLNAME$']
      }
    };
    const modal = this.as.openModal(
      {
        title: 'project.project.startApprovalProcess',
        width: '580px',
        content: DppFormComponent,
        bodyStyle: { height: '220px' },
        footer: [
          {
            label: 'common.button.cancel',
            type: 'default',
            onClick: (): void => {
              modal.close();
            }
          },
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick: data => {
              const isValid = data.onSubmit();
              const formData = data.getFormData();
              formData.GUID$ = instanceData['GUID$'];
              formData.CLASSNAME$ = instanceData['CLASSNAME$'];
              if (isValid) {
                // 查询实例对象执行过的流程
                getNotFinishedProcess.call(this, formData, instanceData, modal);
                modal.close();
                this.projectManageService
                  .releaseProjectCache({ className: instanceData['CLASSNAME$'], guid: instanceData['GUID$'] })
                  .subscribe();
              }
            }
          }
        ]
      },
      { dppRender: params }
    );
  };

  /**
   * 查询是否已存在未完成的流程
   * @param formData
   * @param getDataValue
   * @param workFlowService
   */
  const getNotFinishedProcess = (
    formData: {
      CLASSGUID$: string;
      CLASSNAME$: string;
      GUID$: string;
      TEMPLATE: string;
      TEMPLATE$TITLE: string;
      DESCRIPTION: string;
    },
    getDataValue: NzSafeAny,
    modal: DppNzModalRef
  ): void => {
    forkJoin([loadRoot$()])
      .pipe(
        tap(([rootData]) => {
          taskHasEND2 = rootData[0]?.['HASEND2'];
        }),
        switchMap(() =>
          this.projectManageService.getNotFinishedProcess(
            formData.GUID$,
            getDataValue['CLASSGUID$'],
            formData.CLASSNAME$,
            formData['TEMPLATE']
          )
        )
      )
      .subscribe({
        next: res => {
          if (res.success) {
            let guid = '';
            if (res?.data) {
              // 存在未完成流程
              let contents = '';
              this.dppTranslateService.get('workflow.operation.existWoringWf').subscribe(res => {
                contents = res;
              });
              const fromInstance = res.data?.['FROMINSTANCE'];
              const items = fromInstance?.split('$');
              const titles = this.tranPipe.transform(res.data?.['TITLE']);
              const modal = this.as.openModal({
                title: titles,
                full: 'false',
                linkType: 'modal',
                isInteractive: false,
                content: `${contents}</b>`,
                footer: [
                  {
                    label: 'common.button.cancel',
                    type: 'default',
                    onClick: () => modal.close()
                  },
                  {
                    label: 'common.button.confirm',
                    type: 'primary',
                    onClick: () => {
                      guid = res.data?.['GUID'];
                      const params = {
                        CLASSGUID$: items?.[1],
                        CLASSNAME$: '',
                        GUID$: guid,
                        TEMPLATE: res.data?.['WFTEMPLATEGUID'],
                        TEMPLATE$TITLE: res.data?.['TEMPLATENAME'],
                        DESCRIPTION: res.data?.['DESCRIPTION']
                      };
                      openPageModal.call(this, params, guid);
                      modal.close();
                    }
                  }
                ]
              }) as DppNzModalRef;
            } else {
              const confirmApprovalProject = (): void => {
                const warning = this.tranPipe.transform('common.button.warning');
                if (taskHasEND2) {
                  // 存在项目任务
                  this.projectManageService
                    .checkProjectPlanWorkload({
                      GUID$: instanceData['GUID$'],
                      CLASSNAME$: instanceData['CLASSNAME$']
                    })
                    .subscribe({
                      next: res => {
                        if (res.success) {
                          if (res.data.result === 'WARN') {
                            this.modal.confirm({
                              nzTitle: warning,
                              nzContent: res.data.message,
                              nzOnOk: () => createWorkflow.call(this, formData, getDataValue, guid, modal),
                              nzOnCancel: () => this.setLoading(event, false)
                            });
                          } else if (res.data.result === 'SUCCESS') {
                            createWorkflow.call(this, formData, getDataValue, guid, modal);
                          }
                        }
                      },
                      error: () => this.setLoading(event, false)
                    });
                } else {
                  // this.as.confirm('project.TeamResources.NoProjectTaskWarning', {
                  //   title: warning,
                  //   footer: {
                  //     nzOnOk: () => createWorkflow.call(this, formData, getDataValue, guid, modal),
                  //     nzOnCancel: () => this.setLoading(event, false)
                  //   }
                  // });
                  const msg = this.tranPipe.transform('project.TeamResources.NoProjectTaskWarning');
                  this.modal.confirm({
                    nzTitle: warning,
                    nzContent: msg,
                    nzOnOk: () => createWorkflow.call(this, formData, getDataValue, guid, modal),
                    nzOnCancel: () => this.setLoading(event, false)
                  });
                }
              };
              confirmApprovalProject();
            }
          } else {
            this.dppMessageService.error(`${res.errorCode}:${res.errorMsg}`);
          }
        },
        error: () => {
          this.setLoading(event, false);
        }
      });
  };

  const createWorkflow = (
    formData: FinishedProcessParam,
    getDataValue: CreateProcessParam,
    guid: string,
    modal: DppNzModalRef
  ): void => {
    this.setLoading(event, true);
    this.projectManageService
      .createWorkflow(formData['TEMPLATE'], '', '', formData.DESCRIPTION, formData.GUID$, getDataValue.CLASSGUID$)
      .subscribe({
        next: ele => {
          this.setLoading(event, false);
          guid = ele['data']!['GUID'];
          if (ele.success) {
            if (ele.data) {
              // 关闭模态框
              modal.close();
              this.dppMessageService.success('workflow.operation.createWfSuccess');
              openPageModal.call(this, formData, guid);
            } else {
              this.dppMessageService.error('basic.modalTip.operationfailed');
            }
          } else {
            this.dppMessageService.error(`${ele.errorCode}:${ele.errorMsg}`);
          }
        },
        error: () => {
          this.setLoading(event, false);
        }
      });
  };

  const openPageModal = (formData: FinishedProcessParam, guid: string): void => {
    const property = {
      title: `创建流程(${formData.TEMPLATE$TITLE})`,
      uiType: 'page',
      routePath: '/page',
      baseUri: this.systemConfig.getConfig().pdm
    };
    const params = {
      dppRender: {
        name: 'sysApprovePage',
        guid,
        paramsAddData: true,
        DESCRIPTION: formData['DESCRIPTION'],
        CREATEUSERNAME: formData['CREATEUSERNAME']
      }
    };
    this.as.openBlank(property, params);
  };
}

