sysProjectTemplateRoleBatchDeleteAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const projectData = table.dppRender.data as { GUID$: string; CLASSGUID$: string };
  const checkedNodes = table.getCheckedNodeList();
  const selectNodes1: RowNode[] = []; // guid有(保存过)
  const selectNodes2: RowNode[] = []; // guid没有(反之)
  checkedNodes.map(item => {
    if (!item.origin['GUID'] && !item.origin['END2#GUID']) {
      selectNodes2.push(item);
    } else {
      selectNodes1.push(item);
    }
  });
  if (selectNodes2.length > 0) {
    if (selectNodes1.length === 0) {
      this.dppMessageService.success('common.operation.operationSuccess');
    }
    table.deleteNode(selectNodes2);
    // return;
  }
  if (selectNodes1.length > 0) {
    let params = {
      guid: projectData?.['GUID$'],
      classGuid: projectData?.['CLASSGUID$'],
      roleGuidList: selectNodes1.map(item => item.origin['GUID'] || item.origin['END2#GUID'])
    };

    this.projectManageService.batchDeleteProjectRole(params).subscribe(res => {
      if (res.success && res.data) {
        // 总数量 成功数量  失败数量
        const { successCnt, totalCnt, errorCnt } = res.data;
        if (successCnt && successCnt === totalCnt) {
          this.dppMessageService.success('common.operation.deleteSuccess');
          table.refreshData();
        } else {
          // this.errorMessageService.showMessage(event, res);
          this.batchError(res.data);
          //全部失败， 不需要刷新表格
          if (totalCnt === errorCnt) return;
          table.refreshData();
        }
      }
    });
  }
}

editTeamResourceTableAction(event: CellSaveEvent): Observable<DppResponse<any>> {
  const isNull = Object.values(event.editChancedRowData as object).includes(null);
