  const rowData = event.data as { ROLENAME: string; GUID: string; DESCRIPTION: string };
  const table = this.getContentCom(event) as DppTableComponent;
  const projectData = table.dppRender.data as { CLASSGUID$: string; GUID$: string };

  let props: any = {};
  Object.entries(event.editChancedRowData as object).map(([key, val]) => {
    props[key] = val;
  });
  const params = {
    DESCRIPTION: props['DESCRIPTION'] ?? rowData['DESCRIPTION'],
    GUID: rowData['GUID'],
    ROLENAME: props['ROLENAME'] ?? rowData['ROLENAME'],
    TYPECLASSGUID: projectData?.['CLASSGUID$'],
