  //       // table.refreshData();
  //       this.dppMessageService.success('编辑角色成功！');
  //     }
  //   }
  // });
  return this.projectManageService.saveProjectRole(params).pipe(
    map(i => {
      const updateData = {};
      Object.keys(i.data!).forEach(key => {
        updateData[key.replace('END2#', '')] = i.data![key];
      });
      return {
        errorCode: '',
        errorMsg: '',
        success: true,
        data: updateData
      };
    }),
    tap(() => {
      this.dppMessageService.success('common.modalTip.editSucceed');
    })
