      content: DppFormComponent,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(formCpn: DppFormComponent) {
            const isValid = formCpn.onSubmit();
            const formData = formCpn.getFormData() as DppSafeAny;

            const params: Array<{
              TYPECLASSGUID?: string;
              TYPEGUID?: string;
              ROLENAME: string;
              DESCRIPTION: string;
            }> = [];
            formData.forEach((item: { ROLENAME: string; DESCRIPTION: string }) => {
              params.push({
                TYPECLASSGUID: projectData?.['CLASSGUID$'],
                TYPEGUID: projectData?.['GUID$'],
                ROLENAME: item.ROLENAME,
                DESCRIPTION: item.DESCRIPTION ?? ''
              });
            });
            if (isValid) {
              formCpn.setLoading(true);
              this.loading = true;
              that.projectManageService.batchNewProjectRole(params).subscribe({
                next: res => {
                  if (res.success && res.data) {
                    formCpn.setLoading(false);
                    this.loading = false;
                    modal.close();
                    // 总数量 成功数量  失败数量
                    const { successCnt, totalCnt, errorCnt, details } = res.data;
                    const successCreated = details
                      .filter((item: any) => item.result === 'SUCCESS')
                      .map((item: any) => item.data);
                    const addIndex = table.getAllNodes().length + 1;
                    if (successCnt && successCnt === totalCnt) {
                      that.dppMessageService.success('common.operation.newSuccess');
                      // table.refreshData();
                      table.applyTransaction({
                        add: successCreated,
                        addIndex
                      });
                    } else {
                      // this.errorMessageService.showMessage(event, res);
                      that.batchError(res.data);
                      //全部失败， 不需要刷新表格
                      if (totalCnt === errorCnt) return;
                      // table.refreshData();
                      table.applyTransaction({
                        add: successCreated,
                        addIndex
                      });
                    }
                  }
                },
                error: err => {
                  formCpn.setLoading(false);
                  this.loading = false;
                }
              });
            }
          }
        }
      ]
    },
    {
      dppRender: formParams
    }
  );
}

batchError(originData: any): void {
  const errDatas = new Array();
  const errDatas_ = (originData.details as unknown as IBatchDataDetails[]).filter(
    (i: IBatchDataDetails) => i.result !== 'SUCCESS'
  );
  errDatas_.map((i: IBatchDataDetails) => {
    let tranMess = '';
    if (Array.isArray(i.message)) {
      i.message.forEach((mess, index, arr) => {
        const tran = this.tranPipe.transform(mess, i.data);
        if (index !== arr.length - 1) {
          tranMess += `${tran};`;
        } else {
          tranMess += `${tran}`;
        }
      });
    } else {
      tranMess = this.tranPipe.transform(i.message, i.data);
    }

    errDatas.push({
      ...i.data,
      message: tranMess,
      ROWCOUNT$: errDatas_.length
    });
  });
  this.dppMessageService.customBatchMessage(
    'error',
    {
      actionName: '',
      successCnt: originData.successCnt,
      errorCnt: originData.errorCnt,
      warnCnt: originData.errorCnt,
      totalCnt: originData.totalCnt
    },
    () => {
      const render: IRenderParameterNew<IUiModel> = {
        name: 'sysBatchErrorNotIdTable',
        mParams: {
          mode: ModeTypeEnum.EDIT,
          canSet: 'N',
          canExport: 'true',
          canSize: 'N'
        },
        data: errDatas as unknown as Record<string, unknown>,
        dParams: {}
      };
      this.as.openModal(
        {
          title: '批量处理结果',
          uiType: 'table',
          isInteractive: true,
          openModalCloseDrawer: false,
          footer: 'noFooter',
          width: '80%',
          height: '50vh'
        },
        {
          dppRender: render
        }
      );
    }
  );
}

