sysTeamResourceAddMembersAction(event: EventInterface): void {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const allNodes = table.getAllNodes();
  const nodeGuidMap = new Map<string, RowNode[]>();
  allNodes.forEach(node => {
    const guid = node.origin['END2#ROLEGUID'];
    if (!nodeGuidMap.has(guid)) {
      nodeGuidMap.set(guid, []);
    }
    nodeGuidMap.get(guid)?.push(node);
  });

  const tableRow = this.getRowData(event) as any;
  const projectData = table.dppRender.data as { GUID$: string; CLASSGUID$: string; OWNERPROJECT: string };
  const rowChildrenNodes = nodeGuidMap.get(tableRow['END2#GUID']) || [];

  let memberIds: Array<{
    guid: string;
    isSelected: boolean;
    title: string;
    type: string;
    sort: string;
    projectGuid: string;
  }> = rowChildrenNodes.map(item => {
    return {
      guid: item.origin['END2#USERGUID'],
      isSelected: true,
      title: item.origin['END2#NAME'],
      type: item.origin['END2#DATATYPE'],
      sort: 'team',
      projectGuid: projectData?.['GUID$']
    };
  })!;
  const modal = this.as.openModal(
    {
      title: 'project.TeamResources.addMembers',
      openModalCloseDrawer: false,
      content: SelectiveIntegrationComponent,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: (c: SelectiveIntegrationComponent) => {
            const { user } = c.getSelectedAll();
            const params = {
              guid: projectData?.['GUID$'],
              classGuid: projectData?.['CLASSGUID$'],
              roleGuid: tableRow['END2#GUID'],
              userGuidList: user.map(item => item.origin['GUID']) as string[]
            };
            this.projectManageService.addUserToRole(params).subscribe({
              next: res => {
                const node = allNodes.find(item => item.origin['END2#GUID'] === tableRow['END2#GUID'])!;
                const route = this.tableUtil.getRoute(node);
                rowChildrenNodes.forEach(node => {
                  table.deleteNode(node);
                });

                table.applyTransaction({
                  add: res.data,
                  route
                });
                // table.refreshData();
                node.isExpanded = true;
                this.dppMessageService.success('common.modalTip.editSucceed');
              }
            });
            modal.close();
          }
        }
      ]
    },
    {
      USERS: memberIds ?? [],
      TABS: ['USER']
      // dppRender: {
      //   dParams: {
      //     users: memberIds ?? [],
      //   },
      //   mParams: {
      //     tabs: [
      //       { type: 'USER', title: 'common.aasModal.type.user' }
      //     ]
      //   }
      // }
    }
  );
  modal.afterClose.subscribe(() => {
    this.setLoading(event, false);
  });
}

