sysProjectStructureBatchDownloadAction(event: EventInterface): void {
  this.setLoading(event, true);
  const page = this.getRootPageService(event);
  const instanceData = page.getInstanceData();
  const table = this.getContentCom<DppTableComponent>(event);
  const bs = this.getExeCom<DppButtonComponent>(event);
  const fileName = bs.getUiModel().action!['fileName'];
  const selectDatas = table.getCheckedNodes().map(i => i.origin);
  const taskGuid: string[] = [];
  const deliverItemGuid: string[] = [];
  const deliverableGuid: string[] = [];

  if (selectDatas.length === 0) {
    this.dppMessageService.warning('common.operation.noDataSelected');
    this.setLoading(event, false);
    return;
  }

  selectDatas.forEach(data => {
    const guid = data['END2#GUID$'];
    switch (data['DATATYPE']) {
      case 'task':
        taskGuid.push(guid);
        break;
      case 'deliverableItem':
        deliverItemGuid.push(guid);
        break;
      case 'deliverable':
        deliverableGuid.push(data['END2#GUID']);
        break;
    }
  });

  const param = {
    GUID: instanceData['GUID$'],
    ISLATESTONLY: table.dppRender?.dParams?.['ISLATESTONLY'] || 'N',
    CLASSNAME$: instanceData['CLASSNAME$'],
    ...(taskGuid.length && { taskGuid }),
    ...(deliverItemGuid.length && { deliverItemGuid }),
    ...(deliverableGuid.length && { deliverableGuid })
  };
  this.projectManageService.batchDownloadDeliver(param).subscribe({
    next: res => {
      if (res.success) {
        if (param.ISLATESTONLY === 'Y') {
          this.dppMessageService.success('project.deliverablesList.LatestDeliverableReleased');
        }
        this.setLoading(event, false);
        this.downloadBlob(res.data!, fileName);
      }
    },
    error: err => this.setLoading(event, false)
  });
}

