private downloadBlob(data: Blob, fileName: string): void {
  const downloadUrl = window.URL.createObjectURL(data);
  const link = document.createElement('a');
  link.href = downloadUrl;
  link.download = fileName;
  link.click();
  window.URL.revokeObjectURL(downloadUrl);
}

sysProjectTaskResourceAddAction(event: EventInterface): void {
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.['config']?.['dParams'];
  const ganttTable = this.getTrigger(event) as unknown as DppTableComponent;
  const taskFullName = instanceData['GUID$'];

  const allGanttNode = ganttTable['dppFlattenNodes'];
  const checkedTaskNode = allGanttNode.find(item => item.origin['GUID$'] === taskFullName);
  const ganttCpn = ganttTable.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand);

  const data = table.getTreeNodes() as RowNode[];
  const tableIsExecutor = data.filter((item: RowNode) => item.origin['ISEXECUTOR'] === 'Y') as RowNode[];
  let teamIds: Array<{
    guid: string;
    isSelected: boolean;
    title: string;
    type: string;
    sorted: string;
    projectGuid: string;
  }> = [];
  if (data) {
    teamIds = data.map((item: RowNode) => {
      return {
        guid: item.origin['USERGUID'],
        isSelected: true,
        title: item.origin['USERNAME'],
        type: 'USER',
        sorted: 'team',
        projectGuid: instanceData['OWNERPROJECT']
      };
    });
  }
  const modal = this.as.openModal(
    {
      title: 'task.TaskResource.AddTaskResource',
      width: '50%',
      height: '60%',
      openModalCloseDrawer: false,
      content: NotifySelectiveComponent,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(SelectCpn: NotifySelectiveComponent) {
            const contentTips = that.tranPipe.transform('task.title.AddNewTaskResourceTips');
            const tipsModal = that.as.openModal({
              title: '',
              height: '100px',
              content: contentTips,
              openModalCloseDrawer: false,
              footer: [
                {
                  label: 'common.button.cancel',
                  type: 'default',
                  onClick: () => {
                    tipsModal.close();
                  }
                },
                {
                  label: 'common.button.confirm',
                  type: 'primary',
                  onClick: () => {
                    this.loading = true;
                    const team = SelectCpn.displayAreaData;
                    const listMember = team.map((item, index) => {
                      let executor = '0';
                      if (tableIsExecutor.length === 0 && index === 0) {
                        executor = '1';
                      } else {
                        const matchedExecutor = tableIsExecutor.find(
                          (executorItem: RowNode) => item['guid'] === executorItem.origin['USERGUID']
                        );
                        if (matchedExecutor) {
                          executor = '1';
                        }
                      }

                      return {
                        USERGUID: item['origin']['origin']['USERGUID'],
                        PROJECTROLE: item['origin']['origin']['ROLEGUID'],
                        RESOURCERATE: tableIsExecutor.length === 0 && index === 0 ? 100 : 0,
                        ISEXECUTOR: executor
                      };
                    });

                    const userGuidToResourceRate = data.reduce((acc, item) => {
                      acc[item.origin['USERGUID']] = item.origin['RESOURCERATE'];
                      return acc;
                    }, {});

                    listMember.forEach(itey => {
                      if (userGuidToResourceRate[itey.USERGUID] !== undefined) {
                        itey.RESOURCERATE = userGuidToResourceRate[itey.USERGUID];
                      }
                    });

                    const params = {
                      CLASSGUID$: instanceData['CLASSGUID$'],
                      CLASSNAME$: instanceData['CLASSNAME$'],
                      GUID$: instanceData['GUID$'],
                      LISTMEMBER: listMember
                    };

                    // this.projectManageService.

                    that.projectManageService.updateTaskResource(params).subscribe({
                      next: res => {
                        if (res.success) {
                          modal.close();
                          this.loading = false;
                          that.dppMessageService.success('common.operation.AddedSuccessfully');
                          // ganttTable.refreshData();
                          GanttEventUtil.upDataByNode(ganttTable, checkedTaskNode!, res.data, ganttCpn);
                          table.refreshData();
                        }
                      },
                      error: err => {
                        this.loading = false;
                      }
                    });
                    that.sysTaskResourceAdjustProportionAction(event);
                    tipsModal.close();
                  }
                }
              ]
            });
          }
        }
      ]
    },
    {
      TEAM: teamIds ?? [],
      TABS: ['team'],
      dppRender: {
        dParams: {
          type: 'team',
          projectGuid: instanceData['OWNERPROJECT'],
          disabledConfig: {
            disabledType: 'PROJECTROLE',
            contentTab: 'team'
          }
        }
      }
    }
  );
}

sysTaskResourceAdjustProportionAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  // const page = this.getRootPageService(event);
  // const instanceData = page.getInstanceData() as any;
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.['config']?.['dParams'];
  const data = table.getTreeNodes().map(item => deepCopy(item.origin)) as any;
  const tableParams = {
    name: 'sysAdjustProportionTable',
    data: data as Record<string, unknown>
  };
  const modal = this.as.openModal(
    {
      title: 'task.title.AdjustProportionResources',
      width: '50%',
      height: '400px',
      openModalCloseDrawer: false,
      content: DppTableComponent,
      footer: [
        {
          label: 'common.button.save',
          type: 'primary',
          onClick: (tableCpn: DppTableComponent) => {
            const tableData = tableCpn.getTreeNodes();

            const hasEmptyR = tableData.some(item => !item.origin['RESOURCERATE']);
            if (hasEmptyR) {
              // this.dppMessageService.error('task.title.CanNotSetZeroProportionResources');
              // return;
            }

            const ratioTotal = tableData
              .map(item => {
                return Number(item.origin['RESOURCERATE']);
              })
              .reduce((item, current) => item + current, 0);

            if (ratioTotal !== 100) {
              // this.dppMessageService.error(`执行人占比总和为${ratioTotal}%，不等于100%，请重新设置！`);
              const msg = this.tranPipe.transform('project.message.error.totalExecutorProportion', {
                param: ratioTotal
              });
              this.dppMessageService.error(msg);
              return;
            } else {
              const params = {
                CLASSGUID$: instanceData['CLASSGUID$'],
                CLASSNAME$: instanceData['CLASSNAME$'],
                GUID$: instanceData['GUID$'],
                LISTMEMBER: tableData.map((item: RowNode) => {
                  return {
                    USERGUID: item.origin['USERGUID'],
                    PROJECTROLE: item.origin['PROJECTROLE'],
                    RESOURCERATE: Number(item.origin['RESOURCERATE']),
                    ISEXECUTOR: item.origin['ISEXECUTOR'] === 'Y' ? '1' : '0'
                  };
                })
              };
              this.projectManageService.updateTaskResource(params).subscribe({
                next: res => {
                  modal.close();
                  if (res.success) {
                    this.dppMessageService.success('common.modalTip.editSucceed');
                    table.refreshData();
                  }
                },
                error: err => {
                  // this.dppMessageService.error('编辑失败！');
                  table.refreshData();
                }
              });
            }
          }
        }
      ]
    },
    {
      dppRender: tableParams
    }
  );
}

