sysTaskResourceRemoveaction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const rowData = this.getRowData(event) as { ISEXECUTOR: string; GUID: string };

  // 验证是否可以移除
  if (rowData.ISEXECUTOR === 'Y') {
    this.dppMessageService.warning('执行人不能移除！');
    return;
  }

  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.config?.dParams;

  // 获取剩余数据
  const originalData = table.getTreeNodes().map(node => node.origin);
  const filteredData = originalData.filter(item => item['GUID'] !== rowData.GUID);

  // 更新行计数
  const remainData = filteredData.map(item => ({
    ...item,
    ROWCOUNT$: filteredData.length
  }));

  const tableParams = {
    name: 'sysAdjustProportionTable',
    data: remainData
  };

  // 打开调整资源比例的弹窗
  const modal = this.as.openModal(
    {
      title: 'project.title.adjustProportion',
      width: '50%',
      height: '400px',
      openModalCloseDrawer: false,
      content: DppTableComponent,
      footer: [
        {
          label: 'common.button.save',
          type: 'primary',
          onClick: (tableCpn: DppTableComponent) => {
            const tableData = tableCpn.getTreeNodes().map(node => node.origin);

            const hasEmptyR = tableData.some(item => !item['RESOURCERATE']);
            if (hasEmptyR) {
              // this.dppMessageService.error('task.title.CanNotSetZeroProportionResources');
              // return;
            }

            const ratioTotal = tableData.reduce((total, item) => total + Number(item['RESOURCERATE']), 0);

            // 验证资源比例总和
            if (ratioTotal !== 100) {
              // this.dppMessageService.error(`执行人占比总和为${ratioTotal}%，不等于100%，请重新设置！`);
              const msg = this.tranPipe.transform('project.message.error.totalExecutorProportion', {
                param: ratioTotal
              });
              this.dppMessageService.error(msg);
              return;
            }

            const params = {
              CLASSGUID$: instanceData.CLASSGUID$,
              CLASSNAME$: instanceData.CLASSNAME$,
              GUID$: instanceData.GUID$,
              LISTMEMBER: tableData.map(item => ({
                USERGUID: item['USERGUID'],
                PROJECTROLE: item['PROJECTROLE'],
                RESOURCERATE: Number(item['RESOURCERATE']),
                ISEXECUTOR: item['ISEXECUTOR'] === 'Y' ? '1' : '0'
              }))
            };

            this.projectManageService
              .removeTaskMember(rowData)
              .pipe(
                switchMap(res => {
                  if (!res.success) {
                    throw new Error('移除任务成员失败');
                  }
                  return this.projectManageService.updateTaskResource(params);
                }),
                tap(res => {
                  if (res.success) {
                    this.dppMessageService.success('common.operation.removeSucceed');
                    modal.close();
                    table.refreshData();
                  } else {
                    throw new Error('更新任务资源失败');
                  }
                })
              )
              .subscribe({
                error: err => {
                  this.dppMessageService.error(err.message || '操作失败！');
                  table.refreshData();
                }
              });
          }
        }
      ]
    },
    {
      dppRender: tableParams
    }
  );
}

sysProjectTaskResourceBatchRemoveAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const checkedNodes = table.getCheckedNodeList();
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.['config']?.['dParams'];

  // 获取剩余数据item['GUID'] !== checkedNodes.GUID
  const originalData = table.getTreeNodes().map(node => node.origin);
  const filteredData = originalData.filter(item => {
    return !checkedNodes.some(node => node.origin['GUID'] === item['GUID']);
  });

  // 更新行计数
  const remainData = filteredData.map(item => ({
    ...item,
    ROWCOUNT$: filteredData.length
  }));

  const tableParams = {
    name: 'sysAdjustProportionTable',
    data: remainData
  };

  // 打开调整资源比例的弹窗
  const modal = this.as.openModal(
    {
      title: 'project.title.adjustProportion',
      height: '400px',
      openModalCloseDrawer: false,
      content: DppTableComponent,
      footer: [
        {
          label: 'common.button.save',
          type: 'primary',
          onClick: (tableCpn: DppTableComponent) => {
            const tableData = tableCpn.getTreeNodes().map(node => node.origin);

            const hasEmptyR = tableData.some(item => !item['RESOURCERATE']);
            if (hasEmptyR) {
              // this.dppMessageService.error('task.title.CanNotSetZeroProportionResources');
              // return;
            }

            const ratioTotal = tableData.reduce((total, item) => total + Number(item['RESOURCERATE']), 0);

            // 验证资源比例总和
            if (ratioTotal !== 100) {
              // this.dppMessageService.error(`执行人占比总和为${ratioTotal}%，不等于100%，请重新设置！`);
              const msg = this.tranPipe.transform('project.message.error.totalExecutorProportion', {
                param: ratioTotal
              });
              this.dppMessageService.error(msg);
              return;
            }

            const removeParams = {
              CLASSGUID$: instanceData.CLASSGUID$,
              CLASSNAME$: instanceData.CLASSNAME$,
              GUID$: instanceData.GUID$,
              LISTMEMBER: checkedNodes.map(node => node.origin)
            };

            this.projectManageService
              .batchRemoveTaskMember(removeParams)
              .pipe(
                switchMap(res => {
                  if (!res.success) {
                    throw new Error('移除任务成员失败');
                  }
                  modal.close();
                  // 总数量 成功数量  失败数量
                  const { successCnt, totalCnt, errorCnt } = res.data;
                  if (successCnt && successCnt === totalCnt) {
                    this.dppMessageService.success('common.operation.removeSucceed');
                    table.refreshData();
                  } else {
                    // this.errorMessageService.showMessage(event, res);
                    this.batchError(res.data);
                    //全部失败， 不需要刷新表格
                    if (totalCnt === errorCnt) return of();
                    table.refreshData();
                  }
                  const upDateParams = {
                    CLASSGUID$: instanceData.CLASSGUID$,
                    CLASSNAME$: instanceData.CLASSNAME$,
                    GUID$: instanceData.GUID$,
                    LISTMEMBER: filteredData.map(item => ({
                      USERGUID: item['USERGUID'],
                      PROJECTROLE: item['PROJECTROLE'],
                      RESOURCERATE: Number(item['RESOURCERATE']),
                      ISEXECUTOR: item['ISEXECUTOR'] === 'Y' ? '1' : '0'
                    }))
                  };
                  return this.projectManageService.updateTaskResource(upDateParams);
                }),
                tap(res => {
                  if (res.success) {
                    this.dppMessageService.success('common.operation.removeSucceed');
                    modal.close();
                    table.refreshData();
                  } else {
                    throw new Error('更新任务资源失败');
                  }
                })
              )
              .subscribe({
                error: err => {
                  this.dppMessageService.error(err.message || '操作失败！');
                  table.refreshData();
                }
              });
          }
        }
      ]
    },
    {
      dppRender: tableParams
    }
  );
}

