sysProjectPreTaskAddAction(event: EventInterface): void {
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.['config']?.['dParams'];
  const table = this.getContentCom(event) as DppTableComponent;
  const taskFullName = instanceData['GUID$'];

  const ganttTable = this.getTrigger(event) as DppTableComponent;
  const allGanttNode = ganttTable['dppFlattenNodes'];
  const checkedTaskNode = allGanttNode.find(item => item.origin['GUID$'] === taskFullName)!;
  const ganttCpn = ganttTable.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand)!;

  const render = {
    name: 'sysPreTaskForm',
    mParams: {
      mode: ModeTypeEnum.BATCHCREATE,
      isObject: false
    },
    dParams: instanceData
  };

  const modal = this.as.openModal(
    {
      title: 'task.PreTasks.prerequisiteTasks',
      width: '60vw',
      bodyStyle: { height: '400px' },
      openModalCloseDrawer: false,
      closable: true,
      content: DppFormComponent,
      modalSelf: () => modal,
      footer: [
        {
          label: 'common.button.save',
          type: 'primary',
          onClick(formCpn: DppFormComponent) {
            const isValid = formCpn.onSubmit();

            if (isValid) {
              formCpn.setLoading(true);
              this.loading = true;
              const notTransData = formCpn.getNotTranFormData() as DppSafeAny[];

              const params: Array<{
                DELAYTIME: string;
                PRETASKNAME: string;
                PRETASKGUID: string;
                PRETASKGUID$CLASS: string;
                PRETASKGUID$CLASSNAME: string;
                PRETASKGUID$MASTER: string;
                PRETASKTYPE: string;
                PRETASKTYPE$TITLE: string;
                PROJECTGUID: string;
                PROJECTGUID$CLASS: string;
                PROJECTGUID$CLASSNAME: string;
                PROJECTGUID$MASTERFK: string;
                TASKGUID: string;
                TASKGUID$CLASS: string;
                TASKGUID$CLASSNAME: string;
                TASKGUID$MASTER: string;
              }> = [];
              // const formData = Object.keys(formCpn.getNotTranFormData())
              //   .filter(i => !isNaN(Number(i)))
              //   .map(key => ({
              //     ...notTransData[key]
              //   }));
              // console.log(t);
              notTransData.forEach((item: any) => {
                params.push({
                  PRETASKGUID: item['TASKNAME'].origin['GUID$'],
                  PRETASKGUID$CLASS: item['TASKNAME'].origin['CLASSGUID$'],
                  PRETASKGUID$MASTER: item['TASKNAME'].origin['MASTERFK$'],
                  PRETASKGUID$CLASSNAME: item['TASKNAME'].origin['CLASSNAME$'],

                  TASKGUID: item['GUID$'],
                  TASKGUID$CLASS: item['CLASSGUID$'],
                  TASKGUID$MASTER: item['MASTERFK$'],
                  TASKGUID$CLASSNAME: item['CLASSNAME$'],

                  // 项目
                  PROJECTGUID: item['OWNERPROJECT'],
                  PROJECTGUID$CLASS: item['OWNERPROJECT$CLASS'],
                  PROJECTGUID$CLASSNAME: item['OWNERPROJECT$CLASSNAME'],
                  PROJECTGUID$MASTERFK: item['OWNERPROJECT$MASTER'],

                  PRETASKNAME: item['TASKNAME'].name,
                  PRETASKTYPE: item['TYPE'].value,
                  PRETASKTYPE$TITLE: item['TYPE'].label,
                  DELAYTIME: item['DELAYTIME']
                });
              });

              that.projectManageService.preTaskAdd(params).subscribe({
                next: res => {
                  if (res.data && res.success) {
                    modal.close();
                    formCpn.setLoading(false);
                    this.loading = false;
                    // 总数量 成功数量  失败数量
                    const { successCnt, totalCnt, errorCnt } = res.data;
                    if (successCnt && successCnt === totalCnt) {
                      that.dppMessageService.success('common.operation.addSuccess');
                      // ganttTable.refreshData();
                      let targetTask = res.data.details[res.data.details.length - 1].data;
                      GanttEventUtil.upDataByNode(ganttTable, checkedTaskNode, targetTask, ganttCpn);

                      table.refreshData();
                    } else {
                      that.batchError(res.data);
                      // 全部失败， 不需要刷新表格
                      if (totalCnt === errorCnt) return;
                      // 部分成功，刷新表格
                      const successTasks = res.data.details.filter((item: any) => item['result'] === 'SUCCESS');
                      let targetTask = successTasks[successTasks.length - 1].data;
                      GanttEventUtil.upDataByNode(ganttTable, checkedTaskNode, targetTask, ganttCpn);
                      table.refreshData();
                    }
                  }
                },
                error: err => {
                  formCpn.setLoading(false);
                  this.loading = false;
                }
              });
            }
          }
        }
      ]
    },
    { dppRender: render }
  ) as NzModalRef;
}

sysPreTaskDeleteAction(event: EventInterface): void {
  const rowData = this.getRowData(event) as {
    TASKRELATIONGUID: string;
    GUID$: string;
    CLASSNAME$: string;
    CLASSGUID$: string;
  };
  const outterTable = this.getTrigger(event) as unknown as DppTableComponent;
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const pParams = Object.fromEntries(table.queryCondition.params);
  const renderData = table.dppRender.data as { GUID$: string; CLASSNAME$: string };
  const ganttTable = this.getTrigger(event) as DppTableComponent;

  const taskFullName = pParams['KEY'] === 'POST' ? rowData['GUID$'] : renderData['GUID$'];
  const allGanttNode = ganttTable['dppFlattenNodes'];
  const checkedTaskNode = allGanttNode.find(item => item.origin['GUID$'] === taskFullName);
  const ganttCpn = ganttTable.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand);

  const params = {
    TASKRELATIONGUID: rowData['TASKRELATIONGUID'],
    GUID: renderData['GUID$'],
    CLASSNAME: renderData['CLASSNAME$'],
    PREGUID: rowData['GUID$'],
    PRECLASSGUID: rowData['CLASSGUID$']
  };

  const RETURNPRETASKS = pParams['KEY'] === 'POST' ? 'Y' : 'N';
  this.projectManageService.preTaskBatchDelete([params], RETURNPRETASKS).subscribe({
    next: res => {
      if (res.data && res.success) {
        this.dppMessageService.success('common.operation.deleteSuccess');
