sysProjectPreTaskBatchDeleteAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const pParams = Object.fromEntries(table.queryCondition.params);
  const checkedNodes = table.getCheckedNodeList();
  const renderData = table.dppRender.data as { GUID$: string; CLASSNAME$: string };

  const ganttTable = this.getTrigger(event) as DppTableComponent;
  const postTaskGuids = checkedNodes.map(item => item.origin['GUID$']);
  // 删前置任务，选当前任务；删后置任务，选q任务
  const taskGuids = pParams['KEY'] === 'POST' ? postTaskGuids : [renderData['GUID$']];

  const allGanttNode = ganttTable['dppFlattenNodes'];
  const checkedTaskNodes = allGanttNode.filter(item => taskGuids.includes(item.origin['GUID$']));

  const ganttCpn = ganttTable.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand);

  if (checkedNodes.length) {
    let params = checkedNodes.map(item => ({
      TASKRELATIONGUID: item.origin['TASKRELATIONGUID'],
      GUID: renderData['GUID$'],
      CLASSNAME: renderData['CLASSNAME$'],
      PREGUID: item.origin['GUID$'],
      PRECLASSGUID: item.origin['CLASSGUID$']
    }));

    const RETURNPRETASKS = pParams['KEY'] === 'POST' ? 'Y' : 'N';
    this.projectManageService.preTaskBatchDelete(params, RETURNPRETASKS).subscribe({
      next: res => {
        if (res.data && res.success) {
          // 总数量 成功数量  失败数量
          const { successCnt, totalCnt, errorCnt } = res.data;
          if (successCnt && successCnt === totalCnt) {
            let taskCheckedNode;
            let targetTask;
            this.dppMessageService.success('common.operation.deleteSuccess');
            // 删前置任务，刷新当前任务；删后置任务，刷新前置任务
            res.data.details.map((item: any) => {
              // 不能直接给null,
              if (pParams['KEY'] === 'PRE') {
                item.data['PREDECESSORRELATION'] = item.data['PREDECESSORRELATION'] ?? null;
                taskCheckedNode = checkedTaskNodes[0];
                targetTask = item.data;
                // GanttEventUtil.upDataByNode(outterTable, checkedTaskNodes[0], item.data, ganttCpn);
              } else {
                item.data.PRETASKS['PREDECESSORRELATION'] = item.data.PRETASKS['PREDECESSORRELATION'] ?? null;
                taskCheckedNode = checkedTaskNodes.find(itey => itey.origin['GUID$'] === item.data.PRETASKS['GUID$']);
                targetTask = item.data.PRETASKS;
                // GanttEventUtil.upDataByNode(outterTable, taskChecked!, item.data.PRETASKS, ganttCpn);
              }
            });
            GanttEventUtil.upDataByNode(ganttTable, taskCheckedNode!, targetTask, ganttCpn);
            table.refreshData();
          } else {
            this.errorMessageService.showMessage(event, res);
            //全部失败， 不需要刷新表格
            if (totalCnt === errorCnt) return;
            table.refreshData();
          }
        }
      }
    });
  }
}

