cellClickGeneralAction(event: HasModelEventInterface, config?: BlankInterface): CellClickGeneralCall {
  let { classNameKey = 'CLASSNAME$', guidKey = 'GUID$', extraParams } = config || {};
  const rowData = this.getRowData(event as EventInterface);
  let data = rowData;
  if (extraParams) {
    data = Object.assign(rowData, extraParams);
  }
  const model = event.model as ButtonIUiModel;
  const modelProperty = model?.action as Property;

  if (modelProperty?.['classNameKey']) {
    classNameKey = modelProperty['classNameKey'];
  }

  if (modelProperty?.['guidKey']) {
    guidKey = modelProperty['guidKey'];
  }

  let revisionKey = 'REVISIONID$';
  let iterationKey = 'ITERATIONID$';
  if (config?.dataKey) {
    const key$ = config?.dataKey.indexOf('$') !== -1 ? config?.dataKey : config?.dataKey + '$';
    guidKey = config?.dataKey;
    classNameKey = `${key$}CLASSNAME`;
    revisionKey = `${key$}REVISIONID`;
    iterationKey = `${key$}ITERATIONID`;
  }

  const className = data[classNameKey];
  const guid = data[guidKey];
  const revisionid = data[revisionKey];
  const iterationid = data[iterationKey];
  let windowName = `${className}-${guid}-${revisionid}-${iterationid}`;

  // 额外参数
  if (config?.extraTitleKeys) {
    config?.extraTitleKeys.map(item => {
      if (item.includes(':')) {
        const sliceArr = item.split(':');
        windowName += `-${data[sliceArr[1]]}`;
      } else {
        windowName += `-${data[item]}`;
      }
    });
  }

  const needHandleKeys = ['closeOtherDrawer', 'closable', 'mask', 'isInteractive'];
  for (let propertyKey in modelProperty) {
    if (needHandleKeys.includes(propertyKey)) {
      modelProperty[propertyKey] = strBoolean(modelProperty[propertyKey]);
    }
  }
  let key = 'pdm';
  // 属性公用部分
  let property: Property = {
    title: generateTitle(model, data, this.injector),
    mask: false,
    isInteractive: true,
    closable: true,
    closeOtherDrawer: false,
    wrapClassName: `drawer${guid}-${className}`,
    ...modelProperty
  };
  // 判断baseUri
  let baseUri = data['BASEURI'];
  if (!baseUri) {
    // 后端没有返回的情况下，内置支持ppm和pdm的区分
    const toPpmClassNames = ['ProjectTemplate', 'Project', 'PMTask', 'PMTaskTemplate', 'PMChange'];
    key = toPpmClassNames.includes(className) ? 'ppm' : 'pdm';
    baseUri = this.configService.getConfig()[key];
  } else {
    key = baseUri;
  }
  // 处理参数
  let params = handleRenderParam(
    model?.action as unknown as Record<string, string> || {},
    data as Record<string, string>,
    this.express,
    true
  );
  let newParams = assembTileParams(params);
  // 如果模型中没有配置数据参数，则使用内置的key去取
  if (!params['guid'] && guid && newParams['dParams']) {
    newParams['dParams']['guid'] = guid;
    newParams['dParams']['className'] = className;
  }

  if (config?.extraDParams) {
    newParams['dParams'] = Object.assign(newParams['dParams']!, config.extraDParams);
  }
  return {
    property,
    model,
    newParams,
    baseUri,
    key,
    className,
    guid,
    windowName,
    rowData,
    extraParams,
    originConfig: config!
  };
}

