sysNewItemNextPageAction(event: EventInterface): void {
  const wizardCom = this.getContentCom<DppWizardComponent>(event);
  const formCom = wizardCom.getWizardHeadInstance<DppFormComponent>(0);
  const formComNext = wizardCom.getWizardHeadInstance<DppFormComponent>(1);
  const formNextService = formComNext.getService();
  const configData = wizardCom?.dppRender?.dParams as CadConfig;
  const formComData = deepCopy(formCom.getFormData<IFoundaton>());

  delete formComData['templateName'];
  const repeatCheckFlag$ = this.hasClassRepeatCheck$(formComData);

  repeatCheckFlag$.subscribe(isVaild => {
    if (!isVaild) {
      return;
    }
    // 只有点击了上一步按钮，才需要同步名称和ID
    const { SYNDRAWINGID, SYNDRAWINGNAME } = configData;
    if (formCom.dppRender.innerSend?.['modify_NAME$'] || formCom.dppRender.innerSend?.['modify_ID$']) {
      const nameCom = formNextService.getFieldCpmByKey<StringComponent>('NAME$');
      const idCom = formNextService.getFieldCpmByKey<StringComponent>('ID$');

      if (SYNDRAWINGNAME === 'Y' && nameCom) {
        nameCom.externalSetValue(formCom.dppRender.innerSend?.['modify_NAME$'] || formComData['NAME$'] || '');
      }
      if (SYNDRAWINGID === 'Y' && idCom) {
        idCom.externalSetValue(formComData['ID$'] || '');
      }
    }

    // 给下一步模块切换准备数据
    formComNext.dppRender.innerSend = formComNext.dppRender?.innerSend || {};
    formComNext.dppRender.innerSend['instance_ID$'] = SYNDRAWINGID === 'Y' ? formComData['ID$'] : '';
    formComNext.dppRender.innerSend['instance_NAME$'] = SYNDRAWINGNAME === 'Y' ? formComData['NAME$'] : '';

    wizardCom.next();
  });
}

cadConfigHandle(config: CadConfigHandleParams): {
  data: Record<string, unknown>;
  expression: string;
} {
  const { SYNDRAWINGID, SYNDRAWINGNAME } = config.configData;
  let formData = config.formData || {};
  let innerSend = {};
  if (config.formCom) {
    formData = config.formCom.getData?.() as Record<string, unknown>;
    innerSend = config.formCom.dppRender.innerSend || {};
  }

  let expression = '';
  if (SYNDRAWINGNAME === 'Y') {
    config.data['NAME$'] = formData?.['NAME$'];
    expression += `NAME$:required=false`;
  } else {
    config.data['NAME$'] = innerSend['modify_NAME$'] || '';
  }
  if (SYNDRAWINGID === 'Y') {
    config.data['ID$'] = formData?.['ID$'];
    expression += `;ID$:editable=false:required=false:placeholder=common.title.DrawIDAndItemAccord`;
  } else {
    config.data['ID$'] = innerSend['modify_ID$'] || '';
  }
  return { data: config.data, expression };
}

