sysBOMAddDeliverablesAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const tableRenderData = { ...table.dppRender.dParams, ...table.dppRender.innerSend?.instanceData } as IFoundaton;
  const node = this.getNode(event) as RowNode;
  const hasChildren = node.getChildren()?.length > 0;
  const rowData = this.getRowData(event);
  const tableName = rowData['HASSPEC'] ? 'sysHasSpecGlobalSearchTable' : 'sysGlobalSearchTable';
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  const modal: DppNzModalRef = this.as.openModal(
    {
      title: 'task.command.addDeliverables',
      // width: '95vw',
      openModalCloseDrawer: false,
      content: DppGlobalSearchComponent,
      full: true,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => modal?.close()
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(modalTable: DppGlobalSearchComponent) {
            const nodes = modalTable.table.getCheckedNodes();
            if (!nodes?.length) {
              return;
            }
            this.loading = true;
            const object = nodes.map(item => {
              return {
                PROJECT: tableRenderData['OWNERPROJECT'],
                DELIVERABLEITEMGUID: rowData.GUID,
                INSTANCEGUID: item?.origin?.['GUID$'],
                INSTANCECLASSGUID: item?.origin?.['CLASSGUID$']
              };
            });
            const tableData = table.getFlatRootNodes();
            _this.taskObjectService.batchSaveDeliverable(object).subscribe({
              next: res => {
                if (res.success) {
                  if (res.data?.successCnt && res.data?.successCnt === res.data?.totalCnt) {
                    _this.dppMessageService.success('common.operation.operationSuccess');
                  } else {
                    _this.errorMessageService.showMessage(event, res);
                  }
                  if (res.data?.successCnt) {
                    table.refreshData(node);
                    if (!hasChildren) {
                      _this.taskObjectService
                        .listDeliveryItem({
                          PROJECT: tableRenderData['OWNERPROJECT'],
                          PROJECT$CLASS: tableRenderData['OWNERPROJECT$CLASS'],
                          TASK: tableRenderData.GUID$!,
                          TASK$CLASS: tableRenderData.CLASSGUID$!,
                          TASK$CLASSNAME: tableRenderData.CLASSNAME$!,
                          TASKGUID: tableRenderData.GUID$!
                        })
                        .pipe(
                          tap(refreshRes => {
                            if (refreshRes.success && refreshRes.data?.length) {
                              refreshRes.data.forEach(item => {
                                if (node?.origin['GUID'] === item['GUID']) {
                                  node.setData({
                                    ...node.origin,
                                    ...item
                                  });
                                }
                              });
                            }
                          })
                        )
                        .subscribe();
                    }
                  }
                  this.loading = false;
                  // 如果全部添加失败，就不关闭
                  if (res.data?.errorCnt && res.data?.errorCnt === res.data?.totalCnt) {
                    return;
                  }
                  modal.close();
                }
              },
              error: err => {
                this.loading = false;
              }
            });
          }
        }
      ]
    },
    {
      dppRender: {
        name: tableName,
        // mParams: {
        isRowCheckable: `$origin['HASAUTH'] == false ? false : true`,
        type: 'ui',
        initShow: 'false',
        menuDataSource: `/rewrite/Common/IAdvSearchService/listMenuItemsForDeliverSearch?className=${rowData['CLASSNAME']
          }&CATEGORYOBJECT=${rowData['CLASSIFICATION$NAME'] || ''}`,
        dataSource: `/rewrite/Common/IAdvSearchService/listItemsOfDeliverSearch?className=${rowData['CLASSNAME']
          }&CATEGORYOBJECT=${rowData['CLASSIFICATION$NAME'] || ''}`
        // }
      }

