sysTaskDeliverablesBatchDeleteAction(event: EventInterface): void {
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.['config']?.['dParams'];
  const ganttTable = this.getTrigger(event) as unknown as DppTableComponent;
  const taskFullName = instanceData['GUID$'];
  const allGanttNode = ganttTable?.['dppFlattenNodes'];
  const checkedTaskNode = allGanttNode?.find(item => item.origin['GUID$'] === taskFullName);
  const ganttCpn = ganttTable?.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand);

  const table = this.getContentCom(event) as DppTableComponent;
  const triggerInstance = table.dppRender.innerSend?.triggerInstance?.() as DppTableComponent;
  const projectData = triggerInstance?.dppRender?.data as IFoundaton;
  const data = table.getCheckedNodeList();
  const tableLength = table.getFlatRootNodes()?.length;
  const dppRenderData = { ...table.dppRender.dParams, ...table.dppRender.innerSend?.instanceData } as IFoundaton;
  const needRemoveNodeMap = new Map<string, RowNode>();
  // 交付物
  const object: Array<{
    projectID?: string;
    taskID?: string;
    GUID: string;
    TASK?: string;
    TASK$CLASS?: string;
    PROJECT?: string;
    PROJECT$CLASS?: string;
  }> = [];
  // 交付项
  const params: Array<{
    projectID?: string;
    taskID?: string;
    GUID: string;
    TASK?: string;
    TASK$CLASS?: string;
    PROJECT?: string;
    PROJECT$CLASS?: string;
  }> = [];
  data.forEach(item => {
    if (item.origin['ISROOT'] != 'Y') {
      object.push({
        GUID: item.origin['GUID'],
        TASK: dppRenderData?.['GUID$']?.toString()!,
        TASK$CLASS: dppRenderData?.['CLASSGUID$']?.toString()!,
        PROJECT: projectData ? projectData.GUID$ : dppRenderData['OWNERPROJECT'],
        PROJECT$CLASS: projectData ? projectData.CLASSGUID$ : dppRenderData['OWNERPROJECT$CLASS']
      });
    } else {
      params.push({
        GUID: item.origin['GUID'],
        TASK: dppRenderData?.['GUID$']?.toString()!,
        TASK$CLASS: dppRenderData?.['CLASSGUID$']?.toString()!,
        PROJECT: projectData ? projectData.GUID$ : dppRenderData['OWNERPROJECT'],
        PROJECT$CLASS: projectData ? projectData.CLASSGUID$ : dppRenderData['OWNERPROJECT$CLASS']
      });
    }
    needRemoveNodeMap.set(item.origin['GUID'], item);
    return {
      GUID: item.origin['GUID']
    };
  });
  if (object?.length) {
    this.setLoading(event, true);
    this.taskObjectService.batchDeleteDeliverable(object).subscribe(res => {
      if (res.success) {
        if (res.data?.successCnt && res.data?.successCnt == res.data?.totalCnt) {
          this.dppMessageService.success('common.operation.operationSuccess');
        }
        if (res.data?.errorCnt) {
          this.errorMessageService.showMessage(event, res);
        }
        this.handelAfterDelete(table, res.data?.details || [], needRemoveNodeMap);
      }
      this.setLoading(event, false);
    });
  } else {
    if (params?.length) {
      this.setLoading(event, true);
      this.taskObjectService.batchDeleteDeliveryItem(params).subscribe(res => {
        if (res.success) {
          if (res.data?.successCnt && res.data?.successCnt == res.data?.totalCnt) {
            this.dppMessageService.success('common.operation.operationSuccess');
          }
          if (res.data?.errorCnt) {
            this.errorMessageService.showMessage(event, res);
          }
          this.handelAfterDelete(table, res.data?.details || [], needRemoveNodeMap);
          if (ganttTable) {
            // 返回的是 错误信息 返回不了项目任务数据
            const length = tableLength - res.data?.successCnt!;
            if (table.getTreeNodes()?.length === 0 || length == 0) {
              instanceData['HASDELIVERYITEM'] = 'N';
              GanttEventUtil.upDataByNode(ganttTable, checkedTaskNode!, instanceData, ganttCpn);
            }
          }
          // table.refreshData().subscribe(resp => {
          // });
        }
        this.setLoading(event, false);
      });
    }
  }
}

sysTaskBatchRemoveAction(event: EventInterface): void {
  const btnComp = this.getExeCom(event) as DppButtonComponent;
  const taskTable = this.getTrigger(event) as unknown as DppTableComponent;
  const ganttComp = taskTable.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand);
  const table = this.getContentCom<DppTableComponent>(event);
  const innerSend = table.beans.modelManage.innerSend as any;

  btnComp.setLoading(true);

  // 获取目标节点和根节点
  const targetNode = innerSend.getTargetNode() as RowNode;
  const rootNode = this.findRootNode(targetNode);

  const checkedNodes = table.getCheckedNodeList();

  // 使用 Map 存储交付项节点，key 为节点 id
  const deliveryNodesMap = new Map(
    checkedNodes.filter(item => item.origin['ISROOT'] === 'Y').map(node => [node.id!, node])
  );

  // 提示选择的数据中含有交付项，是否继续删除
  if (deliveryNodesMap.size > 0) {
    this.actionHandleService.confirm('当前选择的数据中含有交付项，是否继续删除?', {
      title: '提示',
      footer: {
        nzOnOk: () => {
          this.executeRemoveAction(event, btnComp, table, ganttComp, targetNode, rootNode, checkedNodes);
        },
        nzOnCancel: () => {
          btnComp.setLoading(false);
        }
      }
    });
  } else {
    this.executeRemoveAction(event, btnComp, table, ganttComp, targetNode, rootNode, checkedNodes);
  }
}

private findRootNode(node: RowNode): RowNode {
  let currentNode = node;
  while (currentNode.level !== 0) {
    currentNode = currentNode.parentNode!;
  }
  return currentNode;
}

private buildDeliveryItemParams(deliveryItemNodes: RowNode[], baseParams: any): any[] {
  return deliveryItemNodes.map(item => ({
    GUID: item.origin['GUID'],
    TASK: baseParams.taskId,
    TASK$CLASS: baseParams.taskClassId,
    PROJECT: baseParams.projectId,
    PROJECT$CLASS: baseParams.projectClassId
  }));
}

private buildDeliveryParams(deliveryNodes: RowNode[], baseParams: any): any[] {
  return deliveryNodes.map(item => ({
    GUID: item.origin['GUID'],
    TASK: baseParams.taskId,
    TASK$CLASS: baseParams.taskClassId,
    PROJECT: baseParams.projectId,
    PROJECT$CLASS: baseParams.projectClassId,
    ROOTGUID: baseParams.projectId,
    ROOTCLASS: baseParams.projectClassName
  }));
}

sysProcessTaskDeliverablesDeleteAction(event: EventInterface): void {
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instanceData = exeCom.dppRender?.['config']?.['dParams'];
  const ganttTable = this.getTrigger(event) as unknown as DppTableComponent;
  const taskFullName = instanceData['GUID$'];
  const allGanttNode = ganttTable?.['dppFlattenNodes'];
  const checkedTaskNode = allGanttNode?.find(item => item.origin['GUID$'] === taskFullName);
  const ganttCpn = ganttTable?.pageService.getComFnMapByName<GanttComponent>(CommandConstant.ProjectWbsCommand);

  this.setLoading(event, true);
  const table = this.getContentCom<DppTableComponent>(event);
  const dppRenderData = { ...table.dppRender.dParams, ...table.dppRender.innerSend?.instanceData } as IFoundaton;
  const rowData = this.getRowData(event);
  const node = this.getNode(event) as RowNode;
  const hasChildrenOne = node.parentNode?.getChildren()?.length === 1;
  const param = {
    GUID: rowData?.['GUID']?.toString()!,
    TASK: dppRenderData?.['GUID$']?.toString()!,
    TASKGUID: dppRenderData?.['GUID$']?.toString()!,
    TASK$CLASS: dppRenderData?.['CLASSGUID$']?.toString()!,
    PROJECT$CLASS: dppRenderData?.['OWNERPROJECT$CLASS'],
    PROJECT: dppRenderData?.['OWNERPROJECT']
  };
  this.taskObjectService.deleteDeliverable(param, rowData['ISROOT'] == 'Y').subscribe({
    next: res => {
      if (res.success) {
        this.setLoading(event, false);
        this.dppMessageService.success('common.operation.operationSuccess');
        const node = this.getNode(event) as RowNode;
        table.deleteNode(node);
        if (hasChildrenOne && rowData['ISROOT'] !== 'Y') {
          this.taskObjectService
            .listDeliveryItem({
              PROJECT: dppRenderData['OWNERPROJECT'],
              PROJECT$CLASS: dppRenderData['OWNERPROJECT$CLASS'],
              TASK: dppRenderData.GUID$!,
              TASK$CLASS: dppRenderData.CLASSGUID$!,
              TASK$CLASSNAME: dppRenderData.CLASSNAME$!,
              TASKGUID: dppRenderData.GUID$!
            })
            .pipe(
              tap(refreshRes => {
                if (refreshRes.success && refreshRes.data?.length) {
                  refreshRes.data.forEach(item => {
                    if (node?.parentNode?.origin?.['GUID'] === item['GUID']) {
                      node.parentNode!.setData({
                        ...node.parentNode!.origin,
                        ...item
                      });
                    }
                  });
                }
              })
            )
            .subscribe();
        }
        if (ganttTable) {
          GanttEventUtil.upDataByNode(ganttTable, checkedTaskNode!, res.data, ganttCpn);
        }
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

