  const button: DppButtonComponent = this.getExeCom<DppButtonComponent>(event);
  const table = this.getContentCom(event) as unknown as DppTableComponent;

  const value: string = button.value;
  let searchCondition = new QueryCondition(DppQueryConditionOperator.OR);
  searchCondition.addCondition(
    new QueryConditionInfo(SystemClassFieldEnum.NAME, [value], DppQueryConditionOperator.LIKE)
  );
  searchCondition.addCondition(
    new QueryConditionInfo(SystemClassFieldEnum.ID, [value], DppQueryConditionOperator.LIKE)
  );
  // searchCondition.addCondition(new QueryConditionInfo('SPECIFICATION', [value], DppQueryConditionOperator.LIKE));
  if (!value) searchCondition = [] as any;
  table.refreshByCondition(searchCondition);
}

