sysTbBOMDeliverablesNewAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const tableRenderData = { ...table.dppRender.dParams, ...table.dppRender.innerSend?.instanceData } as IFoundaton;
  const dataFlag = this.getExeCom(event) && this.getExeCom<IBaseEventComponent>(event)['node'];
  const rowData = this.getRowData(event);
  const node = this.getNode(event) as RowNode;
  rowData['END2$CLASSNAME'] = rowData['CLASSNAME'];
  dataFlag['origin']['END2$CLASSNAME'] = dataFlag['origin']['CLASSNAME'];
  const params: IFormRender = {
    name: 'sysInstanceAddDeliverablesForm',
    mParams: {
      mode: ModeTypeEnum.STEP,
      initValue: `withMainFile=Y`,
      isObject: false
    },
    dParams: {
      className: rowData?.['CLASSNAME']
    },
    data: {
      CLASSNAME$: rowData?.['CLASSNAME'],
      CLASSIFICATION$NAME: rowData['CLASSIFICATION$NAME'] || '',
      CLASSIFICATION$TITLE: rowData['CLASSIFICATION$TITLE'] || rowData['CLSFITILE'],
      CLASSIFICATION$: rowData['CLASSIFICATION']
    }
  };
  FormCommonEventUtil.stepFormHandle(event, params, {
    okFn: (button, formCpm, modal) => {
      const isValid = formCpm.onSubmit();
      if (!isValid) {
        return;
      }
      const data = formCpm.getFormData<IFoundaton>();
      let obss: Observable<
        Array<{
          type: string;
          res: DppResponse<IFoundaton>;
        }>
      >;
      const request1 = this.tbmProjectService.saveObject(data).pipe(
        map(i => {
          return {
            type: 'save',
            res: i
          };
        })
      );
      obss = forkJoin([request1]);
      button.loading = true;
      obss.subscribe({
        next: resp => {
          const end2Iinstance = resp[0].res.data;
          const param = {
            DELIVERABLEITEMGUID: rowData?.['GUID']!,
            INSTANCEGUID: end2Iinstance?.['GUID$']?.toString()!,
            INSTANCECLASSGUID: end2Iinstance?.['CLASSGUID$']?.toString()!,
            taskID: tableRenderData?.['taskID'],
            projectID: tableRenderData?.['projectID']
          };
          this.tbmProjectService.saveTBDeliverable(param).subscribe({
            next: res => {
              if (res.success) {
                this.dppMessageService.success('common.operation.operationSuccess');
                modal.close();
                table.refreshData(node);
              }
            }
          });
          modal.close();
        },
        error: errRes => {
          button.loading = false;
          if (errRes.type && errRes.type === 'check') {
            const errMsg1 = this.tranPipe.transform('common.title.created');
            const errMsg2 = this.tranPipe.transform(errRes.res.error.errorMessage);
            this.dppMessageService.error(`${errMsg1},${errMsg2}`);
            this.getContentCom<DppTableComponent>(event).refreshData();
            modal.close();
          }
        }
      });
    }
  });
}

