private HandleOcclusionIssues(): void {
  setTimeout(() => {
    const messageElement = document.querySelector('.ant-message');
    if (messageElement instanceof HTMLElement) {
      messageElement.style.top = '60px';
    }
  }, 0);
}

sysTBProjectStructureBatchDownloadAction(event: EventInterface): void {
  this.setLoading(event, true);
  const page = this.getRootPageService(event);
  const instanceData = page.getInstanceData();
  const table = this.getContentCom<DppTableComponent>(event);
  const bs = this.getExeCom<DppButtonComponent>(event);
  const fileName = bs.getUiModel().action!['fileName'];
  const selectDatas = table.getCheckedNodes().map(i => i.origin);
  let taskGuid: string[] = [];
  if (selectDatas.length > 0) {
    selectDatas?.filter(ele => {
      if (ele['DATATYPE'] == 'task' && ele?.['END2#GUID$']) {
        taskGuid.push(ele?.['END2#GUID$']);
      }
    });
  } else {
    const msg = this.tranPipe.transform('common.operation.noDataSelected');
    this.dppMessageService.create('warning', `<div class="tb-BatchDownload-warning">${msg}</div>`);
    this.HandleOcclusionIssues();
    this.setLoading(event, false);
    return;
  }
  const param = {
    GUID: instanceData['GUID$'],
    CLASSNAME$: instanceData['CLASSNAME$'],
    taskGuid: taskGuid
  };
  this.tbmProjectService.batchDownloadTBDeliver(param).subscribe({
    next: res => {
      if (res.success) {
        this.setLoading(event, false);
        this.downloadBlob(res.data!, fileName);
      }
    },
    error: err => {
      this.setLoading(event, false);
      setTimeout(() => {
        this.HandleOcclusionIssues();
      }, 100);
    }
  });
}

sysTBDeliveryBatchDownloadAction(event: EventInterface): void {
  this.setLoading(event, true);
  const page = this.getRootPageService(event);
  const instanceData = page.getInstanceData();
  const table = this.getContentCom<DppTableComponent>(event);
  const bs = this.getExeCom<DppButtonComponent>(event);
  const fileName = bs.getUiModel().action!['fileName'];
  const selectDatas = table.getCheckedNodes().map(i => i.origin);

  let deliverableGuid: string[] = [];
  if (selectDatas.length > 0) {
    selectDatas?.filter(ele => {
      deliverableGuid.push(ele?.['END2#GUID']);
    });
  } else {
    const msg = this.tranPipe.transform('common.operation.noDataSelected');
    this.dppMessageService.create('warning', `<div class="tb-BatchDownload-warning">${msg}</div>`);
    setTimeout(() => {
      this.HandleOcclusionIssues();
    }, 0);

    this.setLoading(event, false);
    return;
  }
  const param = {
    GUID: instanceData['GUID$'],
    CLASSNAME$: instanceData['CLASSNAME$'],
    deliverableGuid: deliverableGuid
  };
  this.tbmProjectService.batchDownloadTBDeliver(param).subscribe({
    next: res => {
      if (res.success) {
        this.setLoading(event, false);
        this.downloadBlob(res.data!, fileName);
      }
    },
    error: err => {
      this.setLoading(event, false);
      setTimeout(() => {
        this.HandleOcclusionIssues();
      }, 100);
    }
  });
}

private downloadBlob(data: Blob, fileName: string): void {
  const downloadUrl = window.URL.createObjectURL(data);
  const link = document.createElement('a');
  link.href = downloadUrl;
  link.download = fileName;
  link.click();
  window.URL.revokeObjectURL(downloadUrl);
}
